const EMOJI_PICKER = ["😀","😴","😤","😰","🏠","🎒","🥣","🍽️","🚿","🌙","🧸","🚗","🏊","⚽","👫","📺","🎮","🛋️","🖍️","🎵","📚","🛴","🎨","🍕","🍦","🐶","🐱","🌳","☀️","🌈","⭐","❤️","🎁","🎂","🧩","🪆","🎠","🏖️","🌺","🦋"];

function uid() { return Math.random().toString(36).slice(2, 8); }
function makeCard(picto) {
  return { uid: uid(), id: picto.id, emoji: picto.emoji, label: picto.label, svg: picto.svg ?? null, done: false };
}

const INIT_WEEK = {
  Man:  ["hjem","skole","bad","leg"],
  Tirs: ["hjem","skole","bad","tv"],
  Ons:  ["hjem","skole","svømning","bad"],
  Tors: ["hjem","skole","bad","ro"],
  Fre:  ["hjem","skole","bil","bad"],
  Lør:  ["bil","venner","bad"],
  Søn:  ["spil","ro","sengetid"],
};
function initWeek() {
  const w = {};
  Object.entries(INIT_WEEK).forEach(([day, ids]) => {
    w[day] = ids.map(id => makeCard(PRESET_LIBRARY.find(p => p.id === id)));
  });
  return w;
}

// ─── AI ───────────────────────────────────────────────────────────────────────
// Returns { svg, label } — AI draws an organic children's illustration
async function generatePictogram(description) {
  const STYLE = `ILLUSTRATION STYLE — follow exactly:
- Organic, slightly wobbly outlines (not perfect geometry) — like drawn by a loving hand
- stroke="#2A1A0E" stroke-width="4" stroke-linejoin="round" stroke-linecap="round" on ALL shapes
- 2-3 flat pastel fill colors per illustration (pick warm cheerful palette, e.g. #F5A98A #FDDCB5 #7EC8A4 #A8D8EA #F7D488 #C9A4DC)
- One small white circle (opacity="0.75") near top-right of the main shape — the "shine" highlight
- Chunky and simple — max 10 shapes, readable at 64px
- viewBox="0 0 100 100", NO background rect
- NO text, NO fine details, NO thin lines`;

  const r = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-sonnet-4-20250514", max_tokens: 1400,
      messages: [{ role: "user", content:
        `You are illustrating pictogram cards for a children's visual schedule app (used by autistic children age 4–10).

${STYLE}

Draw a pictogram for: "${description}"

EXAMPLE — for "house": a chunky slightly-lopsided rect body (#FDDCB5), a rounded triangle roof (#F5A98A), a small door rect (#C9956A), a tiny square window (#A8D8EA), and one white circle highlight on the roof.

Return ONLY the raw SVG. Start with <svg viewBox="0 0 100 100" and end with </svg>. No markdown, no explanation, nothing else.`
      }]
    })
  });
  const d = await r.json();
  const t = d.content?.find(b => b.type === "text")?.text || "";
  const m = t.match(/<svg[\s\S]*?<\/svg>/i);
  if (!m) return null;
  // Extract a short label from the description
  const labelR = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-haiku-4-5-20251001", max_tokens: 30,
      messages: [{ role: "user", content: `Give a 1-2 word Danish label for: "${description}". Reply with ONLY the label, nothing else.` }]
    })
  });
  const ld = await labelR.json();
  const label = ld.content?.find(b => b.type === "text")?.text?.trim() || description;
  return { svg: m[0], label };
}

// ─── PICTO CARD COMPONENT ─────────────────────────────────────────────────────
function PictoCard({ card, small, dragging, grayscale, accent, scleraUrl, showLabel, onToggle, onRemove, onEdit, onDragStart, onDragEnd }) {
  const ac = accent || "#5B21B6";
  const W = small ? 60 : 76;
  const H = small ? 66 : 84;
  const R = small ? 18 : 24;
  const emojiSz = small ? 26 : 34;
  const effectiveScleraUrl = grayscale ? (scleraUrl || card.sclera_url) : null;
  const cardBg = card.done ? CARD_BG_DONE : (grayscale ? CARD_BG_GRAY : CARD_BG);

  return (
    <div draggable onDragStart={onDragStart} onDragEnd={onDragEnd} style={{
      position: "relative", width: W, flexShrink: 0,
      cursor: "grab", userSelect: "none",
      opacity: dragging ? 0.2 : 1,
      transform: dragging ? "scale(0.88) rotate(-3deg)" : "scale(1)",
      transition: "opacity 0.15s, transform 0.15s",
      display: "flex", flexDirection: "column", alignItems: "center", gap: small ? 4 : 6,
    }}>
      <div onClick={onToggle} style={{
        width: W, height: H, background: cardBg, borderRadius: R,
        display: "flex", alignItems: "center", justifyContent: "center",
        cursor: onToggle ? "pointer" : "default", position: "relative",
        border: "none",
        boxSizing: "border-box",
      }}>
        {!card.done && !grayscale && (
          <div style={{ position: "absolute", top: small ? 7 : 9, right: small ? 9 : 11, width: small ? 7 : 9, height: small ? 7 : 9, borderRadius: "50%", background: "rgba(255,255,255,0.65)", pointerEvents: "none" }} />
        )}
        {effectiveScleraUrl
          ? <img src={effectiveScleraUrl} alt={card.label} style={{ width: Math.round(H * 0.88), height: Math.round(H * 0.88), objectFit: "contain" }} />
          : card.svg
            ? <div style={{ filter: card.done ? "grayscale(1) opacity(0.5)" : grayscale ? "grayscale(1) brightness(3)" : "none", lineHeight: 0 }}
                dangerouslySetInnerHTML={{ __html: card.svg.replace(/<svg/, `<svg width="${Math.round(H * 0.7)}" height="${Math.round(H * 0.7)}"`) }} />
            : <span style={{ fontSize: emojiSz, lineHeight: 1, filter: card.done ? "grayscale(1) opacity(0.5)" : grayscale ? "grayscale(1) brightness(3)" : "none" }}>{card.emoji}</span>
        }
        {card.done && (
          <div style={{
            position: "absolute", inset: 0, borderRadius: R,
            background: `${ac}55`,
            backdropFilter: "blur(2px)",
            WebkitBackdropFilter: "blur(2px)",
            display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
            gap: small ? 2 : 4,
            animation: "doneOverlay 0.35s cubic-bezier(0.34,1.56,0.64,1)",
          }}>
            <div style={{
              width: small ? 28 : 36, height: small ? 28 : 36,
              borderRadius: "50%",
              background: ac,
              display: "flex", alignItems: "center", justifyContent: "center",
              boxShadow: `0 3px 12px ${ac}80`,
              animation: "checkPop 0.4s cubic-bezier(0.34,1.56,0.64,1) 0.1s both",
            }}>
              <Icon name="check" size={small ? 18 : 24} color="#FFFFFF" />
            </div>
            {!small && <span style={{ fontSize: 9, fontWeight: 900, color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", letterSpacing: 0.5, textTransform: "uppercase", textShadow: `0 1px 4px ${ac}` }}>Klaret!</span>}
          </div>
        )}
      </div>

      {onRemove && <button onClick={e => { e.stopPropagation(); onRemove(); }} style={{ position: "absolute", top: -8, right: -8, width: 22, height: 22, borderRadius: "50%", background: "#C41830", border: "2px solid #FFFFFF", color: "#FFFFFF", fontSize: 12, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 900, zIndex: 10 }}><Icon name="close" size={12} color="#FFFFFF" /></button>}
      {onEdit && <button onClick={e => { e.stopPropagation(); onEdit(); }} style={{ position: "absolute", top: -8, left: -8, width: 22, height: 22, borderRadius: "50%", background: "#4A18A0", border: "2px solid #FFFFFF", color: "#FFFFFF", fontSize: 11, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 900, zIndex: 10 }}><Icon name="edit" size={11} color="#FFFFFF" /></button>}
      {showLabel && (
        <span style={{ fontSize: small ? 8 : 10, fontWeight: 800, color: card.done ? "#9A9090" : "#1A1410", fontFamily: "'Nunito', sans-serif", textAlign: "center", lineHeight: 1.2, maxWidth: W + 8, overflow: "hidden", display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical" }}>
          {card.label}
        </span>
      )}
    </div>
  );
}

// ─── CARD EDITOR OVERLAY ──────────────────────────────────────────────────────
// Full editor: change label, emoji, color. AI regenerate or pick emoji.
function CardEditorOverlay({ theme, card, onSave, onDelete, onClose, isNew }) {
  const acc  = theme ? theme.accent : acc;
  const grad = theme ? theme.grad : "linear-gradient(135deg,#7C3AED,#4F46E5)";
  const [label, setLabel]     = useState(card?.label || "");
  const [emoji, setEmoji]     = useState(card?.emoji || "🏠");
  const [aiSvg, setAiSvg]     = useState(card?.svg || null);
  const [aiInput, setAiInput] = useState(label || "");
  const [loading, setLoading] = useState(false);
  const [tab, setTab]         = useState("emoji"); // "emoji" | "ai"
  const [emojiSearch, setEmojiSearch] = useState("");

  const previewBg = CARD_BG;

  const generate = async () => {
    if (!aiInput.trim()) return;
    setLoading(true);
    try {
      const res = await generatePictogram(aiInput.trim());
      if (res) { setAiSvg(res.svg); if (!label) setLabel(res.label || aiInput.trim()); }
    } catch {}
    setLoading(false);
  };

  const filteredEmoji = emojiSearch
    ? EMOJI_PICKER.filter(() => true) // show all when searching — emoji have no searchable text
    : EMOJI_PICKER;

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(26,8,64,0.55)", zIndex: 600, display: "flex", alignItems: "flex-end", justifyContent: "center", backdropFilter: "blur(8px)" }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{
        background: "#FFFFFF", borderRadius: "28px 28px 0 0",
        width: "100%", maxWidth: 430,
        padding: "20px 20px 48px", maxHeight: "92vh", overflowY: "auto",
        boxShadow: "0 -8px 40px rgba(26,8,64,0.25)",
      }}>
        <div style={{ width: 40, height: 5, background: `${acc}40`, borderRadius: 99, margin: "0 auto 16px" }} />
        <div style={{ fontSize: 20, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif", marginBottom: 20, display: "flex", alignItems: "center", gap: 8 }}>
          <Icon name={isNew ? "plus" : "edit"} size={20} color="#1A0840" />
          {isNew ? "Nyt kort" : "Rediger kort"}
        </div>

        {/* Preview + color picker row */}
        <div style={{ display: "flex", gap: 16, alignItems: "flex-start", marginBottom: 20 }}>
          {/* Live preview */}
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6, flexShrink: 0 }}>
            <div style={{ width: 76, height: 84, background: previewBg, borderRadius: 24, display: "flex", alignItems: "center", justifyContent: "center", position: "relative" }}>
              <div style={{ position: "absolute", top: 9, right: 11, width: 9, height: 9, borderRadius: "50%", background: "rgba(255,255,255,0.65)" }} />
              {aiSvg
                ? <div style={{ lineHeight: 0 }} dangerouslySetInnerHTML={{ __html: aiSvg.replace(/<svg/, '<svg width="52" height="52"') }} />
                : <span style={{ fontSize: 34 }}>{emoji}</span>}
            </div>
            <span style={{ fontSize: 11, fontWeight: 800, color: "#1A1410", fontFamily: "'Nunito', sans-serif", textAlign: "center", maxWidth: 84 }}>{label || "—"}</span>
          </div>

          {/* Right: label + color */}
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", fontWeight: 800, textTransform: "uppercase", letterSpacing: 1, marginBottom: 6 }}>Navn</div>
            <input value={label} onChange={e => setLabel(e.target.value)} placeholder="Hvad hedder aktiviteten?"
              style={{ width: "100%", background: `${acc}12`, border: "2px solid #DDD0F0", borderRadius: 12, padding: "10px 14px", fontSize: 15, color: "#1A0840", outline: "none", fontFamily: "'Nunito', sans-serif", fontWeight: 700, boxSizing: "border-box", marginBottom: 12 }}
            />
  
          </div>
        </div>

        {/* Tab switcher */}
        <div style={{ display: "flex", background: `${acc}12`, borderRadius: 14, padding: 4, marginBottom: 16 }}>
          {[["emoji", "Standard"], ["ai", "Lav en ny"]].map(([id, lbl]) => (
            <button key={id} onClick={() => setTab(id)} style={{
              flex: 1, padding: "10px 0", borderRadius: 10,
              background: tab === id ? "#FFFFFF" : "transparent",
              color: tab === id ? "#1A0840" : "#6A5A50",
              border: "none", cursor: "pointer",
              fontFamily: "'Nunito', sans-serif", fontWeight: 900, fontSize: 13,
              boxShadow: tab === id ? "0 2px 6px rgba(0,0,0,0.1)" : "none",
            }}>{lbl}</button>
          ))}
        </div>

        {/* Emoji tab */}
        {tab === "emoji" && (
          <>

            <div style={{ display: "grid", gridTemplateColumns: "repeat(8, 1fr)", gap: 8 }}>
              {EMOJI_PICKER.map(em => (
                <button key={em} onClick={() => { setEmoji(em); setAiSvg(null); }} style={{
                  fontSize: 24, padding: "6px 2px", background: emoji === em && !aiSvg ? `${acc}40` : "transparent",
                  border: emoji === em && !aiSvg ? "2px solid #4A18A0" : "2px solid transparent",
                  borderRadius: 10, cursor: "pointer",
                }}>{em}</button>
              ))}
            </div>
          </>
        )}

        {/* AI tab */}
        {tab === "ai" && (
          <>
            <div style={{ display: "flex", gap: 8, background: `${acc}12`, borderRadius: 14, padding: "6px 6px 6px 14px", border: "2px solid #DDD0F0", marginBottom: 12 }}>
              <input value={aiInput} onChange={e => setAiInput(e.target.value)}
                onKeyDown={e => e.key === "Enter" && generate()}
                placeholder="Beskriv billedet…"
                style={{ flex: 1, background: "transparent", border: "none", fontSize: 14, color: "#1A0840", outline: "none", fontFamily: "'Nunito', sans-serif", fontWeight: 600 }}
              />
              <button onClick={generate} disabled={loading || !aiInput.trim()} style={{
                padding: "10px 14px", borderRadius: 10,
                background: loading || !aiInput.trim() ? `${acc}40` : acc,
                color: loading || !aiInput.trim() ? "#6A5A50" : "#FFFFFF",
                border: "none", cursor: "pointer", fontSize: 13, fontWeight: 800, fontFamily: "'Nunito', sans-serif"
              }}>{loading ? "⏳" : "Tegn"}</button>
            </div>
            {loading && (
              <div style={{ textAlign: "center", padding: "20px 0" }}>
                <div style={{ display: "flex", justifyContent: "center", gap: 10, marginBottom: 10 }}>
                  {["#F5922A","#E8657A","#4BAD6A"].map((c, i) => (
                    <div key={i} style={{ width: 16, height: 16, borderRadius: "50%", background: c, animation: `bb 0.7s ease-in-out ${i*0.14}s infinite alternate` }} />
                  ))}
                </div>
                <style>{`@keyframes bb { from { transform:translateY(0) } to { transform:translateY(-10px) } }`}</style>
                <div style={{ fontSize: 13, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", fontWeight: 700 }}>Tegner…</div>
              </div>
            )}
            {aiSvg && !loading && (
              <div style={{ display: "flex", alignItems: "center", gap: 14, background: `${acc}12`, borderRadius: 14, padding: "12px 16px" }}>
                <div style={{ width: 60, height: 60, background: CARD_BG, borderRadius: 16, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                  <div style={{ lineHeight: 0 }} dangerouslySetInnerHTML={{ __html: aiSvg.replace(/<svg/, '<svg width="38" height="38"') }} />
                </div>
                <div>
                  <div style={{ fontSize: 13, fontWeight: 800, color: "#1A0840", fontFamily: "'Nunito', sans-serif", marginBottom: 4 }}>Tegning klar! ✓</div>
                  <button onClick={() => setAiSvg(null)} style={{ background: "none", border: "none", color: "#6A5A50", fontSize: 12, cursor: "pointer", fontFamily: "'Nunito', sans-serif", fontWeight: 600, padding: 0, textDecoration: "underline" }}>Fjern og brug emoji</button>
                </div>
              </div>
            )}
          </>
        )}

        {/* Action buttons */}
        <div style={{ display: "flex", gap: 10, marginTop: 20 }}>
          {!isNew && onDelete && (
            <button onClick={() => { onDelete(); onClose(); }} style={{
              padding: "14px 16px", background: "transparent", border: "2px solid #DDD0F0",
              borderRadius: 16, color: "#C41830", cursor: "pointer",
              fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 13
            }}><Icon name="trash" size={15} color="#C41830" style={{marginRight:5}} />Slet</button>
          )}
          <button onClick={onClose} style={{
            flex: 1, padding: "14px 0", background: "transparent",
            border: "2px solid #DDD0F0", borderRadius: 16,
            fontSize: 14, color: "#6A5A50", cursor: "pointer",
            fontFamily: "'Nunito', sans-serif", fontWeight: 800
          }}>Annuller</button>
          <button
            disabled={!label.trim()}
            onClick={() => { onSave({ emoji, label: label.trim(), svg: aiSvg || null }); onClose(); }}
            style={{
              flex: 2, padding: "14px 0",
              background: label.trim() ? acc : `${acc}40`,
              color: label.trim() ? "#FFFFFF" : "#6A5A50",
              border: "none", borderRadius: 16,
              fontSize: 15, cursor: label.trim() ? "pointer" : "not-allowed",
              fontFamily: "'Nunito', sans-serif", fontWeight: 900
            }}>Gem kort</button>
        </div>
      </div>
    </div>
  );
}

// ─── ADD TO DAY OVERLAY ───────────────────────────────────────────────────────
function AddToDayOverlay({ picto, onAdd, onClose, theme, week }) {
  const [added, setAdded] = useState(null); // which day was just added
  const acc = theme.accent;
  const grad = theme.grad;

  const handleAdd = (dayShort) => {
    setAdded(dayShort);
    onAdd(dayShort);
    setTimeout(onClose, 700); // brief confirmation flash then close
  };

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(26,8,64,0.5)", zIndex: 550, display: "flex", alignItems: "flex-end", justifyContent: "center", backdropFilter: "blur(6px)" }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{
        background: "#FFFFFF", borderRadius: "28px 28px 0 0",
        width: "100%", maxWidth: 430, padding: "20px 20px 44px",
        boxShadow: "0 -8px 40px rgba(26,8,64,0.2)",
      }}>
        <div style={{ width: 40, height: 5, background: "#DDD0F0", borderRadius: 99, margin: "0 auto 18px" }} />
        {/* Header: shows which picto is being added */}
        <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 20 }}>
          <div style={{ width: 56, height: 60, background: CARD_BG, borderRadius: 16, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 28, flexShrink: 0, position: "relative" }}>
            <div style={{ position: "absolute", top: 6, right: 8, width: 7, height: 7, borderRadius: "50%", background: "rgba(255,255,255,0.65)" }} />
            {picto.emoji}
          </div>
          <div>
            <div style={{ fontSize: 18, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif" }}>{picto.label}</div>
            <div style={{ fontSize: 13, color: "#6A5A50", fontFamily: "'Nunito', sans-serif" }}>Vælg hvilken dag du vil tilføje den til</div>
          </div>
        </div>
        {/* Day buttons — show current count + confirmation */}
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {DAYS.map(d => {
            const count = (week[d.short] || []).length;
            const isAdded = added === d.short;
            return (
              <button key={d.short} onClick={() => handleAdd(d.short)} style={{
                display: "flex", alignItems: "center", justifyContent: "space-between",
                padding: "12px 18px",
                background: isAdded ? acc : "#F4F0F8",
                border: isAdded ? `2px solid ${acc}` : "2px solid #DDD0F0",
                borderRadius: 16,
                cursor: "pointer", fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 14,
                color: isAdded ? "#FFFFFF" : "#1A0840",
                transition: "all 0.18s ease",
              }}>
                <span style={{ display: "flex", alignItems: "center", gap: 10 }}>
                  {isAdded
                    ? <span style={{ fontSize: 16 }}>✓</span>
                    : <span style={{ fontSize: 14 }}>{d.emoji}</span>}
                  {d.full}
                </span>
                {!isAdded && count > 0 && (
                  <span style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", fontWeight: 700 }}>
                    {count} aktivitet{count !== 1 ? "er" : ""}
                  </span>
                )}
                {isAdded && (
                  <span style={{ fontSize: 12, fontWeight: 700, fontFamily: "'Nunito', sans-serif" }}>Tilføjet!</span>
                )}
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// ─── GENERATE OVERLAY (AI emoji picker from week/day) ────────────────────────
function GenerateOverlay({ onAdd, onClose, theme }) {
  const [input, setInput]       = useState("");
  const [label, setLabel]       = useState("");
  const [loading, setLoading]   = useState(false);
  const [result, setResult]     = useState(null);  // { emoji, label }
  const [error, setError]       = useState(null);

  const generate = async () => {
    if (!input.trim()) return;
    setLoading(true); setError(null); setResult(null);
    try {
      const res = await generatePictogram(input.trim());
      if (res) { setResult(res); setLabel(res.label || input.trim()); }
      else setError("Prøv igen med en anden beskrivelse");
    } catch { setError("Noget gik galt"); }
    setLoading(false);
  };

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(26,8,64,0.5)", zIndex: 500, display: "flex", alignItems: "flex-end", justifyContent: "center", backdropFilter: "blur(6px)" }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{ background: "#FFFFFF", borderRadius: "28px 28px 0 0", width: "100%", maxWidth: 430, padding: "20px 20px 48px", maxHeight: "85vh", overflowY: "auto", boxShadow: "0 -8px 40px rgba(26,8,64,0.2)" }}>
        <div style={{ width: 40, height: 5, background: "#DDD0F0", borderRadius: 99, margin: "0 auto 20px" }} />
        <div style={{ fontSize: 20, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif", marginBottom: 4 }}>Find med AI</div>
        <div style={{ fontSize: 13, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", marginBottom: 16 }}>Beskriv aktiviteten — AI finder det bedste emoji</div>
        <div style={{ display: "flex", gap: 8, background: "#F4F0F8", borderRadius: 14, padding: "6px 6px 6px 14px", border: "2px solid #DDD0F0", marginBottom: 12 }}>
          <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === "Enter" && generate()} placeholder="fx. hoppe på trampolin…"
            style={{ flex: 1, background: "transparent", border: "none", fontSize: 14, color: "#1A0840", outline: "none", fontFamily: "'Nunito', sans-serif", fontWeight: 600 }} />
          <button onClick={generate} disabled={loading || !input.trim()} style={{ padding: "10px 16px", borderRadius: 10, background: loading || !input.trim() ? "#DDD0F0" : theme.accent, color: loading || !input.trim() ? "#6A5A50" : "#FFFFFF", border: "none", cursor: "pointer", fontSize: 13, fontWeight: 800, fontFamily: "'Nunito', sans-serif" }}>{loading ? "⏳" : "Find!"}</button>
        </div>
        {loading && <div style={{ textAlign: "center", padding: "20px 0" }}>
          <div style={{ display: "flex", justifyContent: "center", gap: 10 }}>
            {["#F5922A","#E8657A","#4BAD6A"].map((c,i) => <div key={i} style={{ width: 16, height: 16, borderRadius: "50%", background: c, animation: `bb 0.7s ease-in-out ${i*0.14}s infinite alternate` }} />)}
          </div>
          <style>{`@keyframes bb{from{transform:translateY(0)}to{transform:translateY(-10px)}}`}</style>
          <div style={{ fontSize: 13, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", fontWeight: 700, marginTop: 10 }}>Søger…</div>
        </div>}
        {error && <div style={{ background: "#FEE8EC", borderRadius: 12, padding: "10px 14px", color: "#901840", fontFamily: "'Nunito', sans-serif", fontWeight: 600, fontSize: 13, marginBottom: 12 }}>{error}</div>}
        {result && !loading && <>

          <div style={{ display: "flex", gap: 14, alignItems: "center", background: "#F4F0F8", borderRadius: 16, padding: "12px 14px", marginBottom: 14 }}>
            <div style={{ width: 64, height: 72, background: CARD_BG, borderRadius: 20, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, position: "relative" }}>
              <div style={{ position: "absolute", top: 8, right: 10, width: 8, height: 8, borderRadius: "50%", background: "rgba(255,255,255,0.65)" }} />
              {result.svg
                ? <div style={{ lineHeight: 0 }} dangerouslySetInnerHTML={{ __html: result.svg.replace(/<svg/, '<svg width="44" height="44"') }} />
                : <span style={{ fontSize: 36 }}>{result.emoji}</span>}
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", fontWeight: 700, textTransform: "uppercase", letterSpacing: 1, marginBottom: 6 }}>Navn på kortet:</div>
              <input value={label} onChange={e => setLabel(e.target.value)} style={{ width: "100%", background: "#FFFFFF", border: "2px solid #DDD0F0", borderRadius: 10, padding: "8px 12px", fontSize: 14, color: "#1A0840", outline: "none", fontFamily: "'Nunito', sans-serif", fontWeight: 700, boxSizing: "border-box" }} />
            </div>
          </div>
          <div style={{ display: "flex", gap: 10 }}>
            <button onClick={generate} style={{ flex: 1, padding: "13px 0", background: "transparent", border: "2px solid #DDD0F0", borderRadius: 14, fontSize: 13, color: "#6A5A50", cursor: "pointer", fontFamily: "'Nunito', sans-serif", fontWeight: 800 }}>🔄 Prøv igen</button>
            <button onClick={() => { onAdd({ id: uid(), label: label || input, emoji: "🖼️", svg: result?.svg || null }); onClose(); }} style={{ flex: 2, padding: "13px 0", background: theme.accent, border: "none", borderRadius: 14, fontSize: 14, color: "#FFFFFF", cursor: "pointer", fontFamily: "'Nunito', sans-serif", fontWeight: 900 }}>✓ Brug dette!</button>
          </div>
        </>}
      </div>
    </div>
  );
}

// ─── BANK OVERLAY ─────────────────────────────────────────────────────────────
// ─── SYMBOL SEARCH OVERLAY ───────────────────────────────────────────────────
function SymbolSearchOverlay({ onSelect, onClose, theme }) {
  const acc = theme.accent;
  const grad = theme.grad;
  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searched, setSearched] = useState(false);
  const [selected, setSelected] = useState(null);
  const [labelInput, setLabelInput] = useState("");
  const inputRef = useRef(null);

  useEffect(() => {
    setTimeout(() => inputRef.current && inputRef.current.focus(), 120);
  }, []);

  const doSearch = async (q) => {
    if (!q.trim()) return;
    setLoading(true);
    setSearched(true);
    setResults([]);
    setSelected(null);
    try {
      // Search Sclera symbols by filename from GitHub repo
      // We filter SCLERA_ALL_NAMES (all unique base filenames) by query
      const term = q.toLowerCase().trim();
      const matches = SCLERA_ALL_NAMES
        .filter(name => name.toLowerCase().includes(term))
        .slice(0, 24);
      const normalized = matches.map(name => ({
        id: name.replace(/\s+/g, "_"),
        name: name,
        image_url: SCLERA_BASE + encodeURIComponent(name + " 1.svg"),
      }));
      setResults(normalized);
    } catch(e) {
      setResults([]);
    }
    setLoading(false);
  };

  const handleKey = (e) => {
    if (e.key === "Enter") doSearch(query);
  };

  const pickSymbol = (sym) => {
    setSelected(sym);
    setLabelInput(sym.name || "");
  };

  const confirm = () => {
    if (!selected) return;
    onSelect({
      id: "sclera_" + (selected.id || Math.random().toString(36).slice(2)),
      label: (selected.translations && selected.translations.find(t => t.tLang === 'da') || {}).tName || selected.name || "Aktivitet",
      emoji: "🖼️",
      svg: `<svg viewBox="0 0 100 100" xmlns="http://www.w3.org/2000/svg"><image href="${selected.image_url}" width="100" height="100" preserveAspectRatio="xMidYMid meet"/></svg>`,
      sclera_url: selected.image_url,
    });
    onClose();
  };

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(20,8,50,0.55)", zIndex: 500, display: "flex", alignItems: "flex-end", justifyContent: "center", backdropFilter: "blur(8px)" }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{ background: "#FAFAF8", borderRadius: "28px 28px 0 0", width: "100%", maxWidth: 430, maxHeight: "88vh", display: "flex", flexDirection: "column", boxShadow: "0 -12px 48px rgba(20,8,50,0.22)" }}>
        {/* Handle */}
        <div style={{ width: 40, height: 5, background: "#DDD0F0", borderRadius: 99, margin: "14px auto 0" }} />

        {/* Header */}
        <div style={{ padding: "14px 20px 0" }}>
          <div style={{ fontSize: 18, fontWeight: 900, fontFamily: "'Nunito', sans-serif", color: "#1A1410", marginBottom: 12 }}>
            Søg Sclera-symboler
          </div>

          {/* Search bar */}
          <div style={{ display: "flex", gap: 10 }}>
            <input
              ref={inputRef}
              value={query}
              onChange={e => setQuery(e.target.value)}
              onKeyDown={handleKey}
              placeholder="fx. home, eat, school, swim…"
              style={{
                flex: 1, padding: "13px 16px",
                background: "#FFFFFF", border: `2.5px solid ${acc}40`,
                borderRadius: 999, fontSize: 15, fontFamily: "'Nunito', sans-serif",
                fontWeight: 700, color: "#1A1410", outline: "none",
                boxShadow: "0 2px 8px rgba(0,0,0,0.06)",
              }}
            />
            <button onClick={() => doSearch(query)} style={{
              width: 50, height: 50, borderRadius: 999,
              background: grad, border: "none", cursor: "pointer",
              display: "flex", alignItems: "center", justifyContent: "center",
              boxShadow: `0 4px 12px ${acc}50`, flexShrink: 0,
            }}>
              <Icon name="plus" size={22} color="#FFFFFF" />
            </button>
          </div>

          {/* Language hint */}
          <div style={{ fontSize: 10, color: "#9A8A90", fontFamily: "'Nunito', sans-serif", fontWeight: 700, marginTop: 6, marginBottom: 14 }}>
            Søg på dansk · fx: hjem, spise, skole, sove, svømme
          </div>
        </div>

        {/* Results scroll area */}
        <div style={{ flex: 1, overflowY: "auto", padding: "0 20px 20px" }}>
          {loading && (
            <div style={{ textAlign: "center", padding: "32px 0", color: acc, fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 14 }}>
              Søger…
            </div>
          )}

          {!loading && searched && results.length === 0 && (
            <div style={{ textAlign: "center", padding: "32px 0", color: "#9A8A90", fontFamily: "'Nunito', sans-serif", fontWeight: 700, fontSize: 13 }}>
              Ingen resultater — prøv et andet ord
            </div>
          )}

          {!loading && !searched && (
            <div style={{ textAlign: "center", padding: "24px 0 0", color: "#9A8A90", fontFamily: "'Nunito', sans-serif", fontWeight: 700, fontSize: 12 }}>
              Skriv et ord og tryk søg
            </div>
          )}

          {results.length > 0 && (
            <>
              <div style={{ fontSize: 10, fontWeight: 800, color: "#9A8A90", fontFamily: "'Nunito', sans-serif", letterSpacing: 1, textTransform: "uppercase", marginBottom: 12 }}>
                {results.length} resultater · Tryk for at vælge
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 10 }}>
                {results.map((sym) => {
                  const isSel = selected && selected.id === sym.id;
                  return (
                    <div key={sym.id} onClick={() => pickSymbol(sym)} style={{
                      display: "flex", flexDirection: "column", alignItems: "center", gap: 6,
                      cursor: "pointer",
                    }}>
                      <div style={{
                        width: "100%", aspectRatio: "1",
                        background: "#000000",
                        borderRadius: 18, overflow: "hidden",
                        border: isSel ? `3px solid ${acc}` : "3px solid transparent",
                        boxShadow: isSel ? `0 0 0 3px ${acc}40, 0 6px 18px rgba(0,0,0,0.18)` : "0 3px 10px rgba(0,0,0,0.12)",
                        transform: isSel ? "scale(1.08)" : "scale(1)",
                        transition: "all 0.18s cubic-bezier(0.34,1.4,0.64,1)",
                        display: "flex", alignItems: "center", justifyContent: "center",
                      }}>
                        <img
                          src={sym.image_url}
                          alt={sym.name}
                          style={{ width: "90%", height: "90%", objectFit: "contain" }}
                          loading="lazy"
                        />
                      </div>
                      <span style={{
                        fontSize: 9, fontWeight: 800, color: isSel ? acc : "#6A5A50",
                        fontFamily: "'Nunito', sans-serif", textAlign: "center",
                        lineHeight: 1.2, maxWidth: "100%",
                        overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap",
                      }}>{(sym.translations && sym.translations.find(t => t.tLang === 'da') || {}).tName || sym.name}</span>
                    </div>
                  );
                })}
              </div>
            </>
          )}
        </div>

        {/* Confirm panel — shown when symbol selected */}
        {selected && (
          <div style={{
            padding: "12px 20px 36px",
            borderTop: "1.5px solid #EEE8F0",
            background: "#FFFFFF",
            display: "flex", gap: 12, alignItems: "center",
          }}>
            <div style={{ width: 54, height: 54, background: "#000000", borderRadius: 14, overflow: "hidden", flexShrink: 0 }}>
              <img src={selected.image_url} alt={selected.name} style={{ width: "100%", height: "100%", objectFit: "contain" }} />
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 13, fontWeight: 900, color: "#1A1410", fontFamily: "'Nunito', sans-serif" }}>{(selected.translations && selected.translations.find(t => t.tLang === 'da') || {}).tName || selected.name}</div>
              <div style={{ fontSize: 11, color: "#9A8A90", fontFamily: "'Nunito', sans-serif", fontWeight: 700, marginTop: 2 }}>Tryk for at tilføje</div>
            </div>
            <button onClick={confirm} style={{
              padding: "13px 24px", background: grad,
              border: "none", borderRadius: 999, color: "#FFFFFF",
              fontFamily: "'Nunito', sans-serif", fontWeight: 900, fontSize: 15,
              cursor: "pointer", boxShadow: `0 4px 12px ${acc}50`, flexShrink: 0,
            }}>
              Tilføj ✓
            </button>
          </div>
        )}
      </div>
    </div>
  );
}


// ─── SHARE OVERLAY ───────────────────────────────────────────────────────────
function ShareOverlay({ shareUrl, pin, onClose, theme }) {
  const acc = theme.accent;
  const [copiedLink, setCopiedLink] = useState(false);
  const [copiedPin, setCopiedPin] = useState(false);

  const copyLink = () => {
    navigator.clipboard.writeText(shareUrl).then(() => {
      setCopiedLink(true); setTimeout(() => setCopiedLink(false), 2000);
    });
  };
  const copyPin = () => {
    navigator.clipboard.writeText(pin).then(() => {
      setCopiedPin(true); setTimeout(() => setCopiedPin(false), 2000);
    });
  };

  // Shorten the URL for display
  const shortUrl = shareUrl.length > 40 ? shareUrl.slice(0, 38) + "…" : shareUrl;

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(26,8,64,0.5)", zIndex: 500, display: "flex", alignItems: "flex-end", justifyContent: "center", backdropFilter: "blur(6px)" }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{ background: "#FFFFFF", borderRadius: "28px 28px 0 0", width: "100%", maxWidth: 430, padding: "24px 20px 48px", boxShadow: "0 -8px 40px rgba(26,8,64,0.2)" }}>
        <div style={{ width: 40, height: 5, background: "#DDD0F0", borderRadius: 99, margin: "0 auto 20px" }} />

        {/* Header */}
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 20 }}>
          <div style={{ width: 44, height: 44, borderRadius: 14, background: acc + "18", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
            <Icon name="share" size={22} color={acc} />
          </div>
          <div>
            <div style={{ fontSize: 18, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif", lineHeight: 1 }}>Del med partner</div>
            <div style={{ fontSize: 12, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", marginTop: 3 }}>Vælg hvordan du vil dele ugeplanen</div>
          </div>
        </div>

        {/* Link card */}
        <div style={{ background: "#F8F4FF", borderRadius: 20, padding: "16px", marginBottom: 12, border: "1.5px solid #E0D8F0" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}>
            <span style={{ fontSize: 20 }}>🔗</span>
            <div>
              <div style={{ fontSize: 14, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif" }}>Delelink</div>
              <div style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif" }}>Partner åbner linket i browser</div>
            </div>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <div style={{ flex: 1, background: "#FFFFFF", borderRadius: 10, padding: "9px 12px", fontSize: 12, color: "#6A5880", fontFamily: "monospace", border: "1.5px solid #E0D8F0", overflow: "hidden", whiteSpace: "nowrap", textOverflow: "ellipsis" }}>
              {shortUrl}
            </div>
            <button onClick={copyLink} style={{
              flexShrink: 0, padding: "9px 16px", borderRadius: 10, border: "none", cursor: "pointer",
              background: copiedLink ? "#22C55E" : acc, color: "#FFF",
              fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 13,
              transition: "background 0.2s",
            }}>
              {copiedLink ? "✓" : "Kopiér"}
            </button>
          </div>
        </div>

        {/* PIN card */}
        <div style={{ background: "#F8F4FF", borderRadius: 20, padding: "16px", border: "1.5px solid #E0D8F0" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
            <span style={{ fontSize: 20 }}>🔢</span>
            <div>
              <div style={{ fontSize: 14, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif" }}>PIN-kode</div>
              <div style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif" }}>Partner indtaster koden i appen</div>
            </div>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <div style={{ display: "flex", gap: 6, flex: 1, justifyContent: "center" }}>
              {pin.split("").map((d, i) => (
                <div key={i} style={{ width: 44, height: 52, background: "#FFFFFF", borderRadius: 12, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 26, fontWeight: 900, color: acc, fontFamily: "'Nunito', sans-serif", border: `2px solid ${acc}33` }}>
                  {d}
                </div>
              ))}
            </div>
            <button onClick={copyPin} style={{
              flexShrink: 0, padding: "9px 16px", borderRadius: 10, border: "none", cursor: "pointer",
              background: copiedPin ? "#22C55E" : acc, color: "#FFF",
              fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 13,
              transition: "background 0.2s",
            }}>
              {copiedPin ? "✓" : "Kopiér"}
            </button>
          </div>
          <div style={{ fontSize: 11, color: "#8A7A90", fontFamily: "'Nunito', sans-serif", textAlign: "center", marginTop: 10 }}>Koden ændres automatisk når ugeplanen opdateres</div>
        </div>
      </div>
    </div>
  );
}


// ─── TIMER OVERLAY ───────────────────────────────────────────────────────────
function TimerOverlay({ timerLeft, timerSecs, timerRunning, onStart, onPause, onReset, onClose, onSetTime, theme }) {
  const acc = theme.accent;
  const frac = timerLeft / timerSecs;
  const mins = Math.floor(timerLeft / 60);
  const secs = timerLeft % 60;
  const R = 80, C = 2 * Math.PI * R;
  const dash = C * frac;
  const PRESETS = [
    { label: "5 min",  secs: 300 },
    { label: "10 min", secs: 600 },
    { label: "15 min", secs: 900 },
    { label: "20 min", secs: 1200 },
    { label: "30 min", secs: 1800 },
  ];
  const isDone = timerLeft === 0;

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(26,8,64,0.55)", zIndex: 500, display: "flex", alignItems: "flex-end", justifyContent: "center", backdropFilter: "blur(8px)" }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{ background: "#FFFFFF", borderRadius: "28px 28px 0 0", width: "100%", maxWidth: 430, padding: "24px 24px 52px", boxShadow: "0 -8px 40px rgba(26,8,64,0.2)" }}>
        <div style={{ width: 40, height: 5, background: "#DDD0F0", borderRadius: 99, margin: "0 auto 20px" }} />
        <div style={{ fontSize: 18, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif", textAlign: "center", marginBottom: 24 }}>
          {isDone ? "⏰ Tid!" : "Timer"}
        </div>

        {/* Circular timer */}
        <div style={{ display: "flex", justifyContent: "center", marginBottom: 24 }}>
          <div style={{ position: "relative", width: 200, height: 200 }}>
            <svg width="200" height="200" style={{ transform: "rotate(-90deg)" }}>
              <circle cx="100" cy="100" r={R} fill="none" stroke="#EDE4FA" strokeWidth="12" />
              <circle cx="100" cy="100" r={R} fill="none" stroke={isDone ? "#22C55E" : acc} strokeWidth="12"
                strokeDasharray={`${dash} ${C}`} strokeLinecap="round"
                style={{ transition: "stroke-dasharray 0.5s ease" }} />
            </svg>
            <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
              <span style={{ fontSize: isDone ? 28 : 42, fontWeight: 900, color: isDone ? "#22C55E" : "#1A0840", fontFamily: "'Nunito', sans-serif", lineHeight: 1 }}>
                {isDone ? "Klaret! 🎉" : `${String(mins).padStart(2,"0")}:${String(secs).padStart(2,"0")}`}
              </span>
              {!isDone && <span style={{ fontSize: 12, color: "#8A7A90", fontFamily: "'Nunito', sans-serif", marginTop: 4 }}>minutter tilbage</span>}
            </div>
          </div>
        </div>

        {/* Controls */}
        <div style={{ display: "flex", gap: 12, marginBottom: 20 }}>
          <button onClick={onReset} style={{ flex: 1, padding: "13px 0", background: "#F0EBF8", border: "none", borderRadius: 999, color: "#6A5880", fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 14, cursor: "pointer" }}>
            Nulstil
          </button>
          <button onClick={timerRunning ? onPause : () => onStart(timerSecs)} style={{ flex: 2, padding: "13px 0", background: isDone ? "#22C55E" : acc, border: "none", borderRadius: 999, color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", fontWeight: 900, fontSize: 16, cursor: "pointer", boxShadow: `0 4px 16px ${acc}55` }}>
            {isDone ? "Igen!" : timerRunning ? "⏸ Pause" : "▶ Start"}
          </button>
        </div>

        {/* Time presets */}
        <div style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", fontWeight: 800, letterSpacing: 1, textTransform: "uppercase", marginBottom: 10 }}>Vælg tid</div>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
          {PRESETS.map(p => (
            <button key={p.secs} onClick={() => onSetTime(p.secs)} style={{ padding: "8px 14px", borderRadius: 999, border: `2px solid ${timerSecs === p.secs ? acc : "#E0D8F0"}`, background: timerSecs === p.secs ? acc + "18" : "#F8F4FF", color: timerSecs === p.secs ? acc : "#6A5880", fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 13, cursor: "pointer" }}>
              {p.label}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}


// ─── ROUTINE OVERLAY ─────────────────────────────────────────────────────────
function RoutineOverlay({ onApply, onClose, theme }) {
  const acc = theme.accent;
  const grad = theme.grad;
  const [selected, setSelected] = useState(null);
  const [selectedDays, setSelectedDays] = useState([]);

  const template = selected ? ROUTINE_TEMPLATES.find(r => r.id === selected) : null;

  const toggleDay = (d) => setSelectedDays(prev =>
    prev.includes(d) ? prev.filter(x => x !== d) : [...prev, d]
  );

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(26,8,64,0.5)", zIndex: 450, display: "flex", alignItems: "flex-end", justifyContent: "center", backdropFilter: "blur(6px)" }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{ background: "#FFFFFF", borderRadius: "28px 28px 0 0", width: "100%", maxWidth: 430, padding: "20px 20px 48px", maxHeight: "85vh", overflowY: "auto", boxShadow: "0 -8px 40px rgba(26,8,64,0.2)" }}>
        <div style={{ width: 40, height: 5, background: "#DDD0F0", borderRadius: 99, margin: "0 auto 18px" }} />

        {!template ? (
          <>
            <div style={{ fontSize: 20, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif", marginBottom: 4 }}>Rutineskabeloner</div>
            <div style={{ fontSize: 13, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", marginBottom: 20 }}>Vælg en færdig rutine og tilpas den til jeres hverdag</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
              {ROUTINE_TEMPLATES.map(r => (
                <div key={r.id} onClick={() => setSelected(r.id)} style={{ display: "flex", alignItems: "center", gap: 16, padding: "16px 18px", background: "#F8F4FF", borderRadius: 20, cursor: "pointer", border: `2px solid transparent`, transition: "all 0.15s" }}>
                  <div style={{ width: 52, height: 52, borderRadius: 16, background: r.color + "22", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 26, flexShrink: 0 }}>{r.emoji}</div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 16, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif" }}>{r.label}</div>
                    <div style={{ fontSize: 12, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", marginTop: 2 }}>{r.desc}</div>
                    <div style={{ display: "flex", gap: 4, marginTop: 8, flexWrap: "wrap" }}>
                      {r.cards.map(c => (
                        <span key={c.id} style={{ fontSize: 11, background: r.color + "18", color: r.color, borderRadius: 6, padding: "2px 7px", fontFamily: "'Nunito', sans-serif", fontWeight: 700 }}>{c.emoji} {c.label}</span>
                      ))}
                    </div>
                  </div>
                  <span style={{ fontSize: 20, color: "#8A7A90" }}>›</span>
                </div>
              ))}
            </div>
          </>
        ) : (
          <>
            <button onClick={() => { setSelected(null); setSelectedDays([]); }} style={{ background: "none", border: "none", color: acc, fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 14, cursor: "pointer", padding: 0, marginBottom: 14, display: "flex", alignItems: "center", gap: 6 }}>
              ‹ Tilbage
            </button>
            <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 6 }}>
              <div style={{ width: 48, height: 48, borderRadius: 14, background: template.color + "22", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 24 }}>{template.emoji}</div>
              <div>
                <div style={{ fontSize: 18, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif" }}>{template.label}</div>
                <div style={{ fontSize: 12, color: "#6A5A50", fontFamily: "'Nunito', sans-serif" }}>{template.cards.length} aktiviteter</div>
              </div>
            </div>

            <div style={{ fontSize: 12, fontWeight: 800, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", letterSpacing: 1, textTransform: "uppercase", marginBottom: 10, marginTop: 18 }}>Tilføj til hvilke dage?</div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 6, marginBottom: 20 }}>
              {DAYS.map(d => (
                <button key={d.short} onClick={() => toggleDay(d.short)} style={{ padding: "8px 0", borderRadius: 12, border: `2px solid ${selectedDays.includes(d.short) ? acc : "#E0D8F0"}`, background: selectedDays.includes(d.short) ? acc : "#F8F4FF", color: selectedDays.includes(d.short) ? "#FFF" : "#6A5880", fontFamily: "'Nunito', sans-serif", fontWeight: 900, fontSize: 10, cursor: "pointer", transition: "all 0.15s" }}>
                  {d.short}
                </button>
              ))}
            </div>

            <div style={{ fontSize: 12, fontWeight: 800, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", letterSpacing: 1, textTransform: "uppercase", marginBottom: 10 }}>Aktiviteter i rutinen</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 24 }}>
              {template.cards.map(c => (
                <div key={c.id} style={{ display: "flex", alignItems: "center", gap: 12, padding: "10px 14px", background: "#F8F4FF", borderRadius: 14 }}>
                  <span style={{ fontSize: 22 }}>{c.emoji}</span>
                  <span style={{ fontSize: 14, fontWeight: 700, color: "#1A0840", fontFamily: "'Nunito', sans-serif" }}>{c.label}</span>
                </div>
              ))}
            </div>

            <button
              onClick={() => { if (selectedDays.length > 0) { onApply(template, selectedDays); onClose(); } }}
              style={{ width: "100%", padding: "16px 0", background: selectedDays.length > 0 ? acc : "#D0CCC8", border: "none", borderRadius: 999, color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", fontWeight: 900, fontSize: 16, cursor: selectedDays.length > 0 ? "pointer" : "not-allowed", boxShadow: selectedDays.length > 0 ? `0 4px 16px ${acc}55` : "none", transition: "all 0.2s" }}
            >
              {selectedDays.length === 0 ? "Vælg mindst én dag" : `Tilføj til ${selectedDays.length} dag${selectedDays.length !== 1 ? "e" : ""} →`}
            </button>
          </>
        )}
      </div>
    </div>
  );
}


function BankOverlay({ library, onSelect, onClose, onOpenGenerate, onOpenSclera, theme, grayscale, scleraIcons }) {
  const acc = theme.accent;
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(26,8,64,0.45)", zIndex: 400, display: "flex", alignItems: "flex-end", justifyContent: "center", backdropFilter: "blur(6px)" }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{ background: "#FFFFFF", borderRadius: "28px 28px 0 0", width: "100%", maxWidth: 430, padding: "20px 16px 44px", maxHeight: "76vh", overflowY: "auto", boxShadow: "0 -8px 40px rgba(26,8,64,0.2)" }}>
        <div style={{ width: 40, height: 5, background: "#DDD0F0", borderRadius: 99, margin: "0 auto 18px" }} />



        <div style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", fontWeight: 800, letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 14 }}>Vælg fra biblioteket</div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 14 }}>
          {library.map((p) => {
            // In grayscale mode: prefer sclera symbol, else emoji
            // In colour mode: always show emoji (clear, recognisable)
            const scleraUrl = grayscale && ((scleraIcons && scleraIcons[p.id]) || p.sclera_url);
            const bg = scleraUrl ? "#000000" : (grayscale ? "#F5F0EB" : CARD_BG);
            return (
              <div key={p.id} onClick={() => { onSelect(p); onClose(); }} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 5, cursor: "pointer" }}>
                <div style={{ width: 60, height: 60, background: bg, borderRadius: 18, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 28, position: "relative", boxShadow: "0 2px 8px rgba(0,0,0,0.08)", border: grayscale && !scleraUrl ? "1.5px solid #D0CCC8" : "none" }}>
                  {!grayscale && <div style={{ position: "absolute", top: 7, right: 9, width: 7, height: 7, borderRadius: "50%", background: "rgba(255,255,255,0.65)" }} />}
                  {scleraUrl
                    ? <img src={scleraUrl} alt={p.label} style={{ width: 44, height: 44, objectFit: "contain" }} />
                    : <span>{p.emoji}</span>}
                </div>
                <span style={{ fontSize: 10, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", fontWeight: 700, textAlign: "center" }}>{p.label}</span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}


// ─── PRINT COMPONENTS ─────────────────────────────────────────────────────────

function PrintCard({ card, size = 90, grayscale, scleraUrl, theme }) {
  const bg   = theme ? theme.bg : CARD_BG;
  const done = card.done;
  const sz   = Math.round(size * 0.68);
  return (
    <div style={{
      width: size, flexShrink: 0,
      display: "flex", flexDirection: "column", alignItems: "center", gap: 4,
      pageBreakInside: "avoid",
    }}>
      <div style={{
        width: size, height: Math.round(size * 1.1),
        background: done ? "#D8D4D0" : (grayscale ? "#000000" : bg),
        borderRadius: Math.round(size * 0.22),
        border: "none",
        display: "flex", alignItems: "center", justifyContent: "center",
        position: "relative", overflow: "hidden",
        boxSizing: "border-box",
      }}>
        {!grayscale && !done && (
          <div style={{ position: "absolute", top: "10%", right: "12%", width: "10%", height: "10%", borderRadius: "50%", background: "rgba(255,255,255,0.7)" }} />
        )}
        {(scleraUrl || card.sclera_url)
          ? <img src={scleraUrl || card.sclera_url} alt={card.label} style={{ width: sz, height: sz, objectFit: "contain", opacity: done ? 0.4 : 1 }} />
          : card.svg
            ? <div style={{ lineHeight: 0, filter: done ? "grayscale(1) opacity(0.5)" : grayscale ? "grayscale(1) brightness(3)" : "none" }}
                dangerouslySetInnerHTML={{ __html: card.svg.replace(/<svg/, `<svg width="${sz}" height="${sz}"`) }} />
          : <span style={{ fontSize: Math.round(size * 0.44), lineHeight: 1, filter: done ? "grayscale(1) opacity(0.5)" : grayscale ? "grayscale(1) brightness(3)" : "none" }}>{card.emoji}</span>
        }
      </div>
      <span style={{
        fontSize: Math.round(size * 0.135), fontWeight: 800,
        color: done ? "#888" : "#1A1410",
        fontFamily: "'Nunito', sans-serif",
        textAlign: "center", lineHeight: 1.2,
        maxWidth: size + 8, wordBreak: "break-word",
      }}>{card.label}</span>
    </div>
  );
}

// Landscape A4 week print — 297×210mm usable ~277×190mm
function PrintWeekLayout({ week, selectedDays, theme, grayscale, title }) {
  const acc      = theme.accent;
  const days     = DAYS.filter(d => selectedDays.includes(d.short));
  const maxCards = Math.max(1, ...days.map(d => (week[d.short] || []).length));
  // Scale card size to fit columns — fewer days = bigger cards
  const CARD = days.length <= 3 ? 110 : days.length <= 5 ? 90 : 74;

  return (
    <div style={{
      width: "297mm", minHeight: "210mm",
      background: "#FFFFFF",
      fontFamily: "'Nunito', sans-serif",
      padding: "8mm 8mm 6mm",
      boxSizing: "border-box",
      display: "flex", flexDirection: "column",
    }}>
      <div style={{
        display: "flex", alignItems: "center", justifyContent: "space-between",
        marginBottom: "4mm", paddingBottom: "3mm",
        borderBottom: `3px solid ${acc}`,
      }}>
        <div style={{ fontSize: 22, fontWeight: 900, color: acc }}>{title || "Ugeplan"}</div>
        <div style={{ fontSize: 11, color: "#AAA", fontWeight: 600 }}>
          {new Date().toLocaleDateString("da-DK", { year: "numeric", month: "long" })}
        </div>
      </div>
      <div style={{ display: "flex", gap: "3mm", flex: 1, alignItems: "flex-start" }}>
        {days.map(day => {
          const cards = week[day.short] || [];
          return (
            <div key={day.short} style={{ flex: 1, display: "flex", flexDirection: "column", gap: "2.5mm", borderRight: days.indexOf(day) < days.length - 1 ? `1px solid ${acc}40` : "none", paddingRight: days.indexOf(day) < days.length - 1 ? "3mm" : 0 }}>
              <div style={{ background: acc, borderRadius: 10, padding: "4px 0", textAlign: "center" }}>
                <div style={{ fontSize: Math.max(11, CARD * 0.16), fontWeight: 900, color: "#FFFFFF" }}>{day.short}</div>
                <div style={{ fontSize: Math.max(9, CARD * 0.11), color: "rgba(255,255,255,0.85)", fontWeight: 600 }}></div>
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: "2.5mm", alignItems: "center" }}>
                {cards.map(card => (
                  <PrintCard key={card.uid} card={card} size={CARD} grayscale={grayscale} theme={theme} />
                ))}
                {Array.from({ length: Math.max(0, maxCards - cards.length) }).map((_, i) => (
                  <div key={i} style={{
                    width: CARD, height: Math.round(CARD * 1.1),
                    borderRadius: Math.round(CARD * 0.22),
                    border: "1.5px dashed #DDD",
                  }} />
                ))}
              </div>
            </div>
          );
        })}
      </div>
      <div style={{ marginTop: "3mm", fontSize: 8, color: "#CCC", textAlign: "center" }}>Lavet med Ugeplan-appen</div>
    </div>
  );
}

function PrintDayLayout({ week, selectedDays, theme, grayscale, title }) {
  const acc  = theme.accent;
  const days = DAYS.filter(d => selectedDays.includes(d.short));
  // For 1 day: big cards portrait. For 2-4 days: side by side portrait columns.
  const isMulti = days.length > 1;
  const CARD = isMulti ? Math.max(60, Math.floor(170 / days.length)) : 100;
  const cols = isMulti ? days.length : 3;

  return (
    <div style={{
      width: "210mm", minHeight: "297mm",
      background: "#FFFFFF",
      fontFamily: "'Nunito', sans-serif",
      padding: "8mm 8mm 6mm",
      boxSizing: "border-box",
      display: "flex", flexDirection: "column",
    }}>
      {/* Title bar */}
      <div style={{
        background: acc, borderRadius: 12,
        padding: isMulti ? "8px 14px" : "10px 18px 12px",
        marginBottom: "5mm",
      }}>
        {isMulti ? (
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div style={{ fontSize: 20, fontWeight: 900, color: "#FFFFFF" }}>{title || "Dagsplan"}</div>
            <div style={{ fontSize: 13, color: "rgba(255,255,255,0.8)", fontWeight: 600 }}>
              {days.map(d => d.short).join(" · ")}
            </div>
          </div>
        ) : (
          <>
            <div style={{ fontSize: 24, fontWeight: 900, color: "#FFFFFF" }}>
              {days[0]?.full} {days[0]?.emoji}
            </div>
            <div style={{ fontSize: 13, color: "rgba(255,255,255,0.85)", fontWeight: 600, marginTop: 2 }}>
              {title || "Dagsplan"}
            </div>
          </>
        )}
      </div>

      {isMulti ? (
        /* Multi-day: columns side by side */
        <div style={{ display: "flex", gap: "4mm", flex: 1, alignItems: "flex-start" }}>
          {days.map(day => {
            const cards = week[day.short] || [];
            return (
              <div key={day.short} style={{ flex: 1, display: "flex", flexDirection: "column", gap: "3mm" }}>
                <div style={{ background: acc, borderRadius: 8, padding: "4px 0", textAlign: "center" }}>
                  <div style={{ fontSize: 12, fontWeight: 900, color: "#FFFFFF" }}>{day.short}</div>
                </div>
                <div style={{ display: "flex", flexDirection: "column", gap: "3mm", alignItems: "center" }}>
                  {cards.map(card => <PrintCard key={card.uid} card={card} size={CARD} grayscale={grayscale} theme={theme} />)}
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        /* Single day: grid */
        <div style={{
          display: "grid",
          gridTemplateColumns: `repeat(${cols}, 1fr)`,
          gap: "5mm", flex: 1, alignContent: "start",
        }}>
          {(week[days[0]?.short] || []).map(card => (
            <div key={card.uid} style={{ display: "flex", justifyContent: "center" }}>
              <PrintCard card={card} size={CARD} grayscale={grayscale} theme={theme} />
            </div>
          ))}
        </div>
      )}

      <div style={{ marginTop: "3mm", fontSize: 8, color: "#CCC", textAlign: "center" }}>Lavet med Ugeplan-appen</div>
    </div>
  );
}

// ─── PRINT OVERLAY WITH LIVE PREVIEW ──────────────────────────────────────────
function PrintOverlay({ week, theme, grayscale, focusDay, scleraIcons, onClose }) {
  const acc = theme.accent;

  // Default selected days: all days that have cards
  const daysWithCards = DAYS.filter(d => (week[d.short] || []).length > 0).map(d => d.short);
  const initDays = daysWithCards.length > 0 ? daysWithCards : [focusDay];

  const [selectedDays, setSelectedDays] = useState(initDays);
  // Smart default: >4 days → landscape week, ≤4 → portrait day
  const [orientation, setOrientation]   = useState(initDays.length > 4 ? "landscape" : "portrait");
  const [bw, setBw]                     = useState(grayscale); // follow app's colour/BW setting
  const [title, setTitle]               = useState("");
  const [isPrinting, setPrinting]       = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  // Auto-switch orientation when day count crosses threshold
  const toggleDay = (short) => {
    setSelectedDays(prev => {
      const next = prev.includes(short) ? prev.filter(d => d !== short) : [...prev, short];
      if (next.length === 0) return prev; // always keep at least 1
      // Auto-switch orientation at threshold
      if (next.length > 4 && orientation === "portrait") setOrientation("landscape");
      if (next.length <= 4 && orientation === "landscape") setOrientation("portrait");
      return next;
    });
  };

  const isLandscape = orientation === "landscape";

  // Preview scale — fit the A4 into the preview area
  // Landscape A4: 297×210mm. Portrait A4: 210×297mm.
  // Preview area ~390px wide, ~320px tall (leaving room for controls)
  const PREVIEW_W     = isLandscape ? 297 : 210;  // mm
  const PREVIEW_H     = isLandscape ? 210 : 297;
  const PREVIEW_AREA  = 370; // px available width
  const PREVIEW_AREA_H = 280; // px available height
  const scaleW        = PREVIEW_AREA / (PREVIEW_W * 3.7795); // mm to px at 96dpi
  const scaleH        = PREVIEW_AREA_H / (PREVIEW_H * 3.7795);
  const scale         = Math.min(scaleW, scaleH);
  const previewPxW    = PREVIEW_W * 3.7795 * scale;
  const previewPxH    = PREVIEW_H * 3.7795 * scale;

  const doPrint = () => {
    setPrinting(true);
    setTimeout(() => { window.print(); setPrinting(false); }, 120);
  };

  const sortedSelected = DAYS.filter(d => selectedDays.includes(d.short)).map(d => d.short);

  return (
    <>
      {/* Hidden print target */}
      <div id="print-root" style={{ display: "none" }}>
        {isLandscape
          ? <PrintWeekLayout week={week} selectedDays={sortedSelected} theme={theme} grayscale={bw} title={title} />
          : <PrintDayLayout  week={week} selectedDays={sortedSelected} theme={theme} grayscale={bw} title={title} />
        }
      </div>

      {/* Full-screen overlay */}
      <div style={{
        position: "fixed", inset: 0, zIndex: 700,
        background: "#F2EEF8",
        display: "flex", flexDirection: "column",
        fontFamily: "'Nunito', sans-serif",
      }}>

        {/* Top bar */}
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: "12px 14px",
          background: "#FFFFFF",
          boxShadow: "0 1px 0 rgba(0,0,0,0.07)",
        }}>
          {/* Ghost button with border */}
          <button onClick={onClose} style={{
            background: "transparent",
            border: "1.5px solid rgba(0,0,0,0.12)",
            color: "#1A0840",
            fontWeight: 800, cursor: "pointer",
            padding: "7px 14px 7px 10px",
            borderRadius: 999,
            display: "flex", alignItems: "center", gap: 5, fontSize: 13,
            letterSpacing: 0.1,
          }}>
            <Icon name="close" size={15} color="#1A0840" /> Luk
          </button>

          <div style={{ fontSize: 14, fontWeight: 900, color: "#1A0840", letterSpacing: -0.3 }}>Udskriv ugeplan</div>

          {/* Filled pill button */}
          <button onClick={() => setShowSettings(s => !s)} style={{
            background: showSettings ? acc : "#F0EBF8",
            color: showSettings ? "#FFFFFF" : acc,
            border: "none", borderRadius: 999,
            fontWeight: 800, cursor: "pointer",
            padding: "7px 14px 7px 10px",
            display: "flex", alignItems: "center", gap: 5, fontSize: 13,
            boxShadow: showSettings ? `0 2px 10px ${acc}50` : "none",
            transition: "all 0.18s",
          }}>
            <Icon name="edit" size={15} color={showSettings ? "#FFFFFF" : acc} /> Indstillinger
          </button>
        </div>

        {/* Day selector strip */}
        <div style={{
          background: "#FFFFFF",
          borderBottom: "1px solid rgba(0,0,0,0.07)",
          padding: "12px 14px 16px",
        }}>
          <div style={{ fontSize: 10, fontWeight: 800, color: "#9B8FA0", letterSpacing: 1.4, textTransform: "uppercase", marginBottom: 10 }}>
            Inkluderede dage
          </div>
          <div style={{ display: "flex", gap: 6 }}>
            {DAYS.map(d => {
              const isOn = selectedDays.includes(d.short);
              const count = (week[d.short] || []).length;
              return (
                <button key={d.short} onClick={() => toggleDay(d.short)} style={{
                  flex: 1,
                  padding: "10px 2px 9px",
                  borderRadius: 14,
                  background: isOn ? acc : "#F5F3F8",
                  color: isOn ? "#FFFFFF" : count > 0 ? "#3D2B6B" : "#C4B8D0",
                  border: "none",
                  cursor: "pointer",
                  fontFamily: "'Nunito', sans-serif",
                  fontWeight: 900,
                  fontSize: 11,
                  display: "flex", flexDirection: "column", alignItems: "center", gap: 4,
                  transition: "all 0.16s cubic-bezier(0.34,1.56,0.64,1)",
                  boxShadow: isOn
                    ? `0 4px 14px ${acc}55, inset 0 1px 0 rgba(255,255,255,0.2)`
                    : "inset 0 1px 0 rgba(255,255,255,0.8)",
                  transform: isOn ? "translateY(-1px)" : "translateY(0)",
                  position: "relative",
                  overflow: "hidden",
                }}>
                  {/* Selection glow effect */}
                  {isOn && <div style={{
                    position: "absolute", inset: 0,
                    background: "linear-gradient(180deg, rgba(255,255,255,0.15) 0%, transparent 60%)",
                    borderRadius: "inherit",
                    pointerEvents: "none",
                  }} />}
                  <span style={{ letterSpacing: 0.2 }}>{d.short}</span>
                  {/* Count pill */}
                  <span style={{
                    minWidth: 18, height: 16, borderRadius: 99,
                    background: isOn ? "rgba(255,255,255,0.22)" : count > 0 ? `${acc}18` : "rgba(0,0,0,0.06)",
                    display: "flex", alignItems: "center", justifyContent: "center",
                    padding: "0 5px",
                    fontSize: 9, fontWeight: 900,
                    color: isOn ? "rgba(255,255,255,0.9)" : count > 0 ? acc : "#C4B8D0",
                  }}>{count}</span>
                </button>
              );
            })}
          </div>
        </div>

        {/* Preview area */}
        <div style={{
          flex: 1, display: "flex", alignItems: "center", justifyContent: "center",
          padding: "16px 12px",
          overflow: "hidden",
        }}>
          <div style={{
            width: previewPxW, height: previewPxH,
            boxShadow: "0 8px 40px rgba(0,0,0,0.18)",
            borderRadius: 6,
            overflow: "hidden",
            flexShrink: 0,
          }}>
            <div style={{
              transform: `scale(${scale})`,
              transformOrigin: "top left",
              width: `${PREVIEW_W * 3.7795}px`,
              height: `${PREVIEW_H * 3.7795}px`,
            }}>
              {isLandscape
                ? <PrintWeekLayout week={week} selectedDays={sortedSelected} theme={theme} grayscale={bw} title={title} />
                : <PrintDayLayout  week={week} selectedDays={sortedSelected} theme={theme} grayscale={bw} title={title} />
              }
            </div>
          </div>
        </div>

        {/* Settings panel */}
        {showSettings && (
          <div style={{
            background: "#FFFFFF",
            borderRadius: "20px 20px 0 0",
            padding: "16px 18px 32px",
            maxHeight: "55vh", overflowY: "auto",
            boxShadow: "0 -4px 24px rgba(0,0,0,0.10)",
          }}>
            <div style={{ width: 36, height: 4, background: "#DDD", borderRadius: 99, margin: "0 auto 18px" }} />

            {/* Orientation */}
            <div style={{ fontSize: 10, color: "#6A5A50", fontWeight: 800, textTransform: "uppercase", letterSpacing: 1, marginBottom: 8 }}>Papirretning</div>
            <div style={{ display: "flex", gap: 8, marginBottom: 18 }}>
              {[
                { id: "landscape", label: "Vandret", sub: "A4 297×210" },
                { id: "portrait",  label: "Lodret",  sub: "A4 210×297" },
              ].map(o => (
                <button key={o.id} onClick={() => setOrientation(o.id)} style={{
                  flex: 1, padding: "12px 6px", borderRadius: 12,
                  background: orientation === o.id ? acc : "#F2EEF8",
                  color: orientation === o.id ? "#FFF" : "#1A0840",
                  border: `2px solid ${orientation === o.id ? acc : "transparent"}`,
                  cursor: "pointer", fontWeight: 800, fontSize: 12,
                  display: "flex", flexDirection: "column", alignItems: "center", gap: 4,
                  boxShadow: orientation === o.id ? `0 3px 10px ${acc}40` : "none",
                }}>
                  <Icon name="print" size={20} color={orientation === o.id ? "#FFF" : acc}
                    style={{ transform: o.id === "landscape" ? "rotate(90deg)" : "none" }} />
                  <span>{o.label}</span>
                  <span style={{ fontWeight: 600, fontSize: 10, opacity: 0.65 }}>{o.sub}</span>
                </button>
              ))}
            </div>

            {/* B&W toggle */}
            <div style={{ fontSize: 10, color: "#6A5A50", fontWeight: 800, textTransform: "uppercase", letterSpacing: 1, marginBottom: 8 }}>Farvetilstand</div>
            <div style={{ display: "flex", gap: 8, marginBottom: 18 }}>
              {[
                { val: false, label: "Farver",    icon: "theme" },
                { val: true,  label: "Sort/hvid", icon: "week" },
              ].map(opt => (
                <button key={String(opt.val)} onClick={() => setBw(opt.val)} style={{
                  flex: 1, padding: "12px 6px", borderRadius: 12,
                  background: bw === opt.val ? (opt.val ? "#000000" : acc) : "#F2EEF8",
                  color: bw === opt.val ? "#FFF" : "#1A0840",
                  border: `2px solid ${bw === opt.val ? (opt.val ? "#000000" : acc) : "transparent"}`,
                  cursor: "pointer", fontWeight: 800, fontSize: 12,
                  display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
                  boxShadow: bw === opt.val ? "0 3px 10px rgba(0,0,0,0.15)" : "none",
                }}>
                  <Icon name={opt.icon} size={18} color={bw === opt.val ? "#FFF" : acc} />
                  <span>{opt.label}</span>
                </button>
              ))}
            </div>

            {/* Title */}
            <div style={{ fontSize: 10, color: "#6A5A50", fontWeight: 800, textTransform: "uppercase", letterSpacing: 1, marginBottom: 8 }}>Overskrift (valgfri)</div>
            <div style={{ background: "#F2EEF8", borderRadius: 12, padding: "4px 6px 4px 14px", border: "2px solid transparent", display: "flex", marginBottom: 4 }}>
              <input value={title} onChange={e => setTitle(e.target.value)}
                placeholder="fx. Maddies uge…"
                style={{ flex: 1, background: "transparent", border: "none", outline: "none", fontSize: 14, color: "#1A0840", fontFamily: "'Nunito', sans-serif", fontWeight: 600, padding: "8px 0" }}
              />
            </div>
          </div>
        )}

        {/* Bottom print button */}
        {!showSettings && (
          <div style={{ padding: "12px 18px 28px", background: "#FFFFFF", boxShadow: "0 -1px 0 rgba(0,0,0,0.07)" }}>
            <button onClick={doPrint} disabled={isPrinting || selectedDays.length === 0} style={{
              width: "100%", padding: "16px 0",
              background: isPrinting || selectedDays.length === 0 ? "#DDD" : acc,
              color: isPrinting || selectedDays.length === 0 ? "#AAA" : "#FFFFFF",
              border: "none", borderRadius: 16,
              fontSize: 16, fontWeight: 900, cursor: isPrinting ? "not-allowed" : "pointer",
              display: "flex", alignItems: "center", justifyContent: "center", gap: 10,
              boxShadow: isPrinting || selectedDays.length === 0 ? "none" : `0 4px 16px ${acc}55`,
            }}>
              <Icon name="print" size={22} color={isPrinting || selectedDays.length === 0 ? "#AAA" : "#FFFFFF"} />
              {isPrinting ? "Gør klar…" : `Udskriv ${selectedDays.length} dag${selectedDays.length !== 1 ? "e" : ""}`}
            </button>
          </div>
        )}
      </div>
    </>
  );
}



// ─── ROUTINE PRINT OVERLAY ────────────────────────────────────────────────────
function RoutinePrintOverlay({ routines, theme, grayscale, onClose }) {
  const acc = theme.accent;
  const grad = theme.grad;
  const [selected, setSelected] = React.useState(routines.map(r => r.id));
  const [bw, setBw] = React.useState(grayscale);
  const [title, setTitle] = React.useState("");
  const [isPrinting, setIsPrinting] = React.useState(false);

  const toggle = (id) => setSelected(prev =>
    prev.includes(id) ? (prev.length > 1 ? prev.filter(x => x !== id) : prev) : [...prev, id]
  );

  const selectedRoutines = routines.filter(r => selected.includes(r.id));

  const doPrint = () => {
    setIsPrinting(true);
    const printEl = document.getElementById("routine-print-root");
    if (printEl) printEl.style.display = "block";
    setTimeout(() => {
      window.print();
      if (printEl) printEl.style.display = "none";
      setIsPrinting(false);
    }, 120);
  };

  return (
    <>
      <div id="routine-print-root" style={{ display: "none" }}>
        <PrintRoutineLayout routines={selectedRoutines} theme={theme} grayscale={bw} title={title} />
      </div>

      <div style={{
        position: "fixed", inset: 0, zIndex: 700,
        background: "#F2EEF8",
        display: "flex", flexDirection: "column",
        fontFamily: "'Nunito', sans-serif",
      }}>
        {/* Top bar */}
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: "14px 16px 12px",
          background: "#FFFFFF",
          boxShadow: "0 1px 0 rgba(0,0,0,0.07)",
        }}>
          <button onClick={onClose} style={{
            background: "rgba(0,0,0,0.05)", border: "none", color: "#1A0840",
            fontWeight: 800, cursor: "pointer", padding: "8px 14px 8px 10px",
            borderRadius: 12, display: "flex", alignItems: "center", gap: 6, fontSize: 14,
          }}>
            <Icon name="close" size={18} color="#1A0840" /> Luk
          </button>
          <div style={{ fontSize: 15, fontWeight: 900, color: "#1A0840" }}>Udskriv rutinestrimler</div>
          <div style={{ width: 80 }} />
        </div>

        {/* Routine selector */}
        <div style={{ background: "#FFFFFF", borderBottom: "1px solid rgba(0,0,0,0.07)", padding: "12px 16px 16px" }}>
          <div style={{ fontSize: 10, fontWeight: 800, color: "#6A5A50", letterSpacing: 1.2, textTransform: "uppercase", marginBottom: 10 }}>
            Vælg rutiner
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {routines.map(r => {
              const on = selected.includes(r.id);
              return (
                <button key={r.id} onClick={() => toggle(r.id)} style={{
                  display: "flex", alignItems: "center", gap: 12,
                  padding: "10px 14px", borderRadius: 14,
                  background: on ? acc + "18" : "#F2EEF8",
                  border: `2px solid ${on ? acc : "transparent"}`,
                  cursor: "pointer", textAlign: "left",
                  boxShadow: on ? `0 2px 8px ${acc}30` : "none",
                  transition: "all 0.15s",
                }}>
                  <div style={{
                    width: 36, height: 36, borderRadius: 10, flexShrink: 0,
                    background: on ? acc + "30" : "#E8E0F0",
                    display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20,
                  }}>{r.emoji}</div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 14, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif" }}>{r.label}</div>
                    <div style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif" }}>{r.cards.length} trin</div>
                  </div>
                  <div style={{
                    width: 22, height: 22, borderRadius: 6,
                    background: on ? acc : "transparent",
                    border: `2.5px solid ${on ? acc : "#C0B0D0"}`,
                    display: "flex", alignItems: "center", justifyContent: "center",
                    flexShrink: 0,
                  }}>
                    {on && <Icon name="check" size={14} color="#FFF" />}
                  </div>
                </button>
              );
            })}
          </div>
        </div>

        {/* Options */}
        <div style={{ padding: "14px 16px", background: "#FFFFFF", borderBottom: "1px solid rgba(0,0,0,0.07)", display: "flex", gap: 10 }}>
          {/* B&W toggle */}
          {[{val:false,label:"Farver",icon:"theme"},{val:true,label:"Sort/hvid",icon:"week"}].map(opt => (
            <button key={String(opt.val)} onClick={() => setBw(opt.val)} style={{
              flex: 1, padding: "10px 6px", borderRadius: 12,
              background: bw === opt.val ? (opt.val ? "#000000" : acc) : "#F2EEF8",
              color: bw === opt.val ? "#FFF" : "#1A0840",
              border: `2px solid ${bw === opt.val ? (opt.val ? "#000000" : acc) : "transparent"}`,
              cursor: "pointer", fontWeight: 800, fontSize: 12,
              display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
              fontFamily: "'Nunito', sans-serif",
            }}>
              <Icon name={opt.icon} size={16} color={bw === opt.val ? "#FFF" : acc} />
              {opt.label}
            </button>
          ))}
        </div>

        {/* Title input */}
        <div style={{ padding: "12px 16px", background: "#FFFFFF", borderBottom: "1px solid rgba(0,0,0,0.07)" }}>
          <div style={{ background: "#F2EEF8", borderRadius: 12, padding: "4px 6px 4px 14px", display: "flex" }}>
            <input value={title} onChange={e => setTitle(e.target.value)}
              placeholder="Overskrift (valgfri)…"
              style={{ flex: 1, background: "transparent", border: "none", outline: "none", fontSize: 14, color: "#1A0840", fontFamily: "'Nunito', sans-serif", fontWeight: 600, padding: "8px 0" }}
            />
          </div>
        </div>

        {/* Preview */}
        <div style={{ flex: 1, overflow: "auto", padding: "16px" }}>
          <div style={{ background: "#FFFFFF", borderRadius: 12, overflow: "hidden", boxShadow: "0 4px 20px rgba(0,0,0,0.10)", transform: "scale(0.85)", transformOrigin: "top center" }}>
            <PrintRoutineLayout routines={selectedRoutines} theme={theme} grayscale={bw} title={title} />
          </div>
        </div>

        {/* Print button */}
        <div style={{ padding: "12px 18px 28px", background: "#FFFFFF", boxShadow: "0 -1px 0 rgba(0,0,0,0.07)" }}>
          <button onClick={doPrint} disabled={isPrinting} style={{
            width: "100%", padding: "16px 0",
            background: isPrinting ? "#DDD" : acc,
            color: isPrinting ? "#AAA" : "#FFFFFF",
            border: "none", borderRadius: 16,
            fontSize: 16, fontWeight: 900, cursor: isPrinting ? "not-allowed" : "pointer",
            display: "flex", alignItems: "center", justifyContent: "center", gap: 10,
            boxShadow: isPrinting ? "none" : `0 4px 16px ${acc}55`,
            fontFamily: "'Nunito', sans-serif",
          }}>
            <Icon name="print" size={22} color={isPrinting ? "#AAA" : "#FFFFFF"} />
            {isPrinting ? "Gør klar…" : `Udskriv ${selected.length} rutine${selected.length !== 1 ? "r" : ""}`}
          </button>
        </div>
      </div>
    </>
  );
}

// ─── PRINT ROUTINE STRIPS ─────────────────────────────────────────────────────
function PrintRoutineLayout({ routines, theme, grayscale, title }) {
  const acc = theme.accent;
  const bg  = theme.bg;
  return (
    <div style={{
      width: "210mm", minHeight: "297mm",
      background: "#FFFFFF", padding: "12mm 14mm",
      fontFamily: "'Nunito', sans-serif",
      boxSizing: "border-box",
    }}>
      {/* Page title */}
      {title && (
        <div style={{ fontSize: 22, fontWeight: 900, color: acc, marginBottom: 8, letterSpacing: -0.5 }}>{title}</div>
      )}

      {routines.map((r, ri) => (
        <div key={r.id} style={{
          marginBottom: 14,
          pageBreakInside: "avoid",
          background: bg,
          borderRadius: 16,
          padding: "12px 14px 14px",
          border: `2.5px solid ${acc}40`,
        }}>
          {/* Routine header */}
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
            <div style={{
              width: 38, height: 38, borderRadius: 12,
              background: acc + "22",
              display: "flex", alignItems: "center", justifyContent: "center",
              fontSize: 22,
            }}>{r.emoji}</div>
            <div>
              <div style={{ fontSize: 16, fontWeight: 900, color: "#1A0840", lineHeight: 1 }}>{r.label}</div>
              <div style={{ fontSize: 11, color: "#6A5A50", marginTop: 2 }}>{r.cards.length} trin</div>
            </div>
          </div>

          {/* Cards strip */}
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
            {r.cards.map((card, ci) => (
              <div key={ci} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 5, pageBreakInside: "avoid" }}>
                {/* Step number */}
                <div style={{
                  width: 22, height: 22, borderRadius: "50%",
                  background: acc, color: "#FFF",
                  display: "flex", alignItems: "center", justifyContent: "center",
                  fontSize: 11, fontWeight: 900,
                }}>{ci + 1}</div>

                {/* Card */}
                <div style={{
                  width: 72, height: 80, borderRadius: 16,
                  background: grayscale ? "#000000" : bg,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  border: `2px solid ${acc}30`,
                  position: "relative", overflow: "hidden",
                }}>
                  {card.svg
                    ? <div style={{ lineHeight: 0, filter: !grayscale ? "none" : "grayscale(1) brightness(3)" }}
                        dangerouslySetInnerHTML={{ __html: card.svg.replace(/<svg/, '<svg width="54" height="54"') }} />
                    : <span style={{ fontSize: 32, filter: grayscale ? "grayscale(1) brightness(3)" : "none" }}>{card.emoji}</span>
                  }
                </div>

                {/* Label */}
                <div style={{
                  fontSize: 10, fontWeight: 800, color: "#1A0840",
                  textAlign: "center", maxWidth: 72, lineHeight: 1.2,
                  wordBreak: "break-word",
                }}>{card.label}</div>

                {/* Checkbox */}
                <div style={{
                  width: 22, height: 22, borderRadius: 6,
                  border: `2.5px solid ${acc}`,
                  background: "transparent",
                }} />
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

// ─── PROFILE HELPERS ─────────────────────────────────────────────────────────
const CHILD_EMOJIS = ["🦁","🐼","🦊","🐸","🐧","🦄","🐨","🐯","🐺","🦋","🐬","🦖"];
function newProfileId() { return "p_" + Math.random().toString(36).slice(2, 9); }
function loadProfiles() {
  try {
    const raw = localStorage.getItem("ugeplan_profiles");
    return raw ? JSON.parse(raw) : null;
  } catch { return null; }
}
function saveProfiles(profiles) {
  try { localStorage.setItem("ugeplan_profiles", JSON.stringify(profiles)); } catch {}
}
function makeProfile(name, themeId, avatar) {
  return { id: newProfileId(), name, themeId, avatar: avatar || CHILD_EMOJIS[0], week: initWeek() };
}

// ─── ONBOARDING ──────────────────────────────────────────────────────────────
const TAB_GUIDE = [
  { icon: "week",     label: "Uge",       desc: "Overblik over hele ugen" },
  { icon: "day",      label: "Dag",       desc: "Detaljeret dagsplan med afkrydsning" },
  { icon: "library",  label: "Bibliotek", desc: "Alle aktivitets-kort samlet" },
  { icon: "routines", label: "Rutiner",   desc: "Morgen, eftermiddag & aften" },
  { icon: "theme",    label: "Tema",      desc: "Farver, piktogrammer & print" },
];

function OnboardingScreen({ onDone, isAddingChild = false }) {
  const STEPS = [
    ...(!isAddingChild ? [{ id: "welcome", emoji: "👋", title: "Velkommen til\nUgeplan!", desc: "En visuel ugeplan der hjælper børn med at forstå og mestre hverdagens aktiviteter.", cta: "Kom i gang" }] : []),
    { id: "name",   emoji: "🌟", title: isAddingChild ? "Nyt barn" : "Hvad hedder barnet?", desc: "Giv barnet et navn.", cta: "Næste", input: true },
    { id: "avatar", emoji: "🎭", title: "Vælg et ikon",  desc: "Så er det nemt at skifte mellem børn.", cta: "Næste", avatar: true },
    { id: "theme",  emoji: "🎨", title: "Vælg et tema",  desc: "Du kan altid ændre det igen.", cta: "Næste", themes: true },
    ...(!isAddingChild ? [{ id: "guide", emoji: "🗺️", title: "Her er din app", desc: "5 faner — alt hvad du behøver.", cta: "Start planlægning", guide: true }] : [{ id: "done_add", emoji: "✅", title: "Klar!", desc: "Barnets ugeplan er oprettet.", cta: "Åbn ugeplan" }]),
  ];
  const [step, setStep] = useState(0);
  const [childName, setChildName] = useState("");
  const [selectedAvatar, setSelectedAvatar] = useState(CHILD_EMOJIS[0]);
  const [selectedTheme, setSelectedTheme] = useState("lyng");
  const current = STEPS[step];
  const theme = THEMES.find(t => t.id === selectedTheme);
  const acc = theme.accent;
  const grad = theme.grad;
  const isLast = step === STEPS.length - 1;

  const handleNext = () => {
    if (isLast) {
      onDone({ childName: childName.trim() || "Barn", themeId: selectedTheme, avatar: selectedAvatar });
    } else {
      setStep(s => s + 1);
    }
  };

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 9999,
      background: theme.bg,
      display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "space-between",
      fontFamily: "'Nunito', sans-serif",
      padding: "0 0 40px",
      maxWidth: 430, margin: "0 auto",
    }}>
      {/* Progress dots */}
      <div style={{ display: "flex", gap: 8, paddingTop: 56, paddingBottom: 0 }}>
        {STEPS.map((_, i) => (
          <div key={i} style={{
            width: i === step ? 24 : 8, height: 8,
            borderRadius: 999,
            background: i === step ? acc : `${acc}40`,
            transition: "all 0.35s cubic-bezier(0.34,1.2,0.64,1)",
          }} />
        ))}
      </div>

      {/* Content */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "0 28px", width: "100%", boxSizing: "border-box", gap: 0 }}>

        {/* Emoji / illustration */}
        {!current.guide && !current.avatar && !current.themes && (
          <div style={{
            fontSize: 80, lineHeight: 1, marginBottom: 28,
            filter: "drop-shadow(0 8px 24px rgba(0,0,0,0.10))",
            animation: "obPop 0.5s cubic-bezier(0.34,1.56,0.64,1)",
          }}>
            {current.id === "done_add" ? selectedAvatar : current.emoji}
          </div>
        )}

        {/* Title */}
        <div style={{
          fontSize: current.guide ? 26 : 32,
          fontWeight: 900, color: "#1A0840",
          textAlign: "center", lineHeight: 1.2,
          marginBottom: 12, whiteSpace: "pre-line",
          letterSpacing: -0.5,
        }}>
          {current.id === "name" && childName ? `Hej, ${childName}! 👋` : current.title}
        </div>

        {/* Desc */}
        <div style={{ fontSize: 16, color: "#6A5A70", textAlign: "center", lineHeight: 1.5, marginBottom: 32, fontWeight: 600 }}>
          {current.desc}
        </div>

        {/* Name input */}
        {current.input && (
          <input
            autoFocus
            placeholder="F.eks. Emma eller Lucas"
            value={childName}
            onChange={e => setChildName(e.target.value)}
            onKeyDown={e => e.key === "Enter" && handleNext()}
            style={{
              width: "100%", boxSizing: "border-box",
              padding: "16px 20px", fontSize: 20, fontWeight: 800,
              fontFamily: "'Nunito', sans-serif", color: "#1A0840",
              background: "#FFFFFF", border: `2.5px solid ${acc}`,
              borderRadius: 20, outline: "none", textAlign: "center",
              boxShadow: `0 4px 20px ${acc}25`,
            }}
          />
        )}

        {/* Theme picker */}
        {current.themes && (
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap", justifyContent: "center", width: "100%" }}>
            {THEMES.map(t => (
              <button key={t.id} onClick={() => setSelectedTheme(t.id)} style={{
                display: "flex", flexDirection: "column", alignItems: "center", gap: 6,
                background: selectedTheme === t.id ? t.accent : "#FFFFFF",
                border: `2.5px solid ${selectedTheme === t.id ? t.accent : "transparent"}`,
                borderRadius: 20, padding: "14px 20px", cursor: "pointer",
                boxShadow: selectedTheme === t.id ? `0 6px 20px ${t.accent}50` : "0 2px 10px rgba(0,0,0,0.08)",
                transition: "all 0.25s cubic-bezier(0.34,1.2,0.64,1)",
                transform: selectedTheme === t.id ? "scale(1.08)" : "scale(1)",
              }}>
                <span style={{ fontSize: 30 }}>{t.icon}</span>
                <span style={{ fontSize: 13, fontWeight: 900, color: selectedTheme === t.id ? "#FFFFFF" : "#1A0840", fontFamily: "'Nunito', sans-serif" }}>{t.label}</span>
              </button>
            ))}
          </div>
        )}

        {/* Avatar picker */}
        {current.avatar && (
          <div style={{ display: "flex", gap: 12, flexWrap: "wrap", justifyContent: "center", width: "100%" }}>
            {CHILD_EMOJIS.map(em => (
              <button key={em} onClick={() => setSelectedAvatar(em)} style={{
                width: 60, height: 60, fontSize: 32,
                background: selectedAvatar === em ? acc : "#FFFFFF",
                border: `2.5px solid ${selectedAvatar === em ? acc : "transparent"}`,
                borderRadius: 18, cursor: "pointer",
                boxShadow: selectedAvatar === em ? `0 6px 20px ${acc}50` : "0 2px 10px rgba(0,0,0,0.08)",
                transition: "all 0.22s cubic-bezier(0.34,1.2,0.64,1)",
                transform: selectedAvatar === em ? "scale(1.12)" : "scale(1)",
                display: "flex", alignItems: "center", justifyContent: "center",
              }}>{em}</button>
            ))}
          </div>
        )}

        {/* Tab guide */}
        {current.guide && (
          <div style={{ display: "flex", flexDirection: "column", gap: 10, width: "100%" }}>
            {TAB_GUIDE.map((item, i) => (
              <div key={item.icon} style={{
                display: "flex", alignItems: "center", gap: 14,
                background: "#FFFFFF", borderRadius: 18, padding: "13px 16px",
                boxShadow: "0 2px 10px rgba(0,0,0,0.07)",
                animation: `obSlide 0.4s ${i * 0.07}s both cubic-bezier(0.34,1.2,0.64,1)`,
              }}>
                <div style={{ width: 42, height: 42, borderRadius: 14, background: grad, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, boxShadow: `0 4px 12px ${acc}40` }}>
                  <Icon name={item.icon} size={20} color="#FFFFFF" />
                </div>
                <div>
                  <div style={{ fontSize: 15, fontWeight: 900, color: "#1A0840" }}>{item.label}</div>
                  <div style={{ fontSize: 12, color: "#8A7A90", fontWeight: 600 }}>{item.desc}</div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* CTA button */}
      <div style={{ width: "100%", padding: "0 28px", boxSizing: "border-box" }}>
        {step > 0 && (
          <button onClick={() => setStep(s => s - 1)} style={{
            width: "100%", padding: "14px", marginBottom: 10,
            background: "transparent", border: "none",
            fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 15,
            color: acc, cursor: "pointer",
          }}>
            ← Tilbage
          </button>
        )}
        <button onClick={handleNext} style={{
          width: "100%", padding: "18px",
          background: grad, border: "none",
          borderRadius: 999, cursor: "pointer",
          fontFamily: "'Nunito', sans-serif", fontWeight: 900, fontSize: 18,
          color: "#FFFFFF", boxShadow: `0 8px 28px ${acc}55`,
          transition: "transform 0.15s",
          letterSpacing: 0.2,
        }}>
          {current.cta} {isLast ? "🚀" : "→"}
        </button>
      </div>

      <style>{`
        @keyframes obPop {
          0% { transform: scale(0.5) rotate(-10deg); opacity: 0; }
          100% { transform: scale(1) rotate(0deg); opacity: 1; }
        }
        @keyframes obSlide {
          0% { transform: translateX(-20px); opacity: 0; }
          100% { transform: translateX(0); opacity: 1; }
        }
      `}</style>
    </div>
  );
}

// ─── MAIN APP ─────────────────────────────────────────────────────────────────
export default function App() {
  // ── Multi-profile state ──
  const [profiles, setProfiles] = useState(() => {
    const saved = loadProfiles();
    return saved && saved.length > 0 ? saved : null;
  });
  const [activeProfileId, setActiveProfileId] = useState(() => {
    try { return localStorage.getItem("ugeplan_active") || null; } catch { return null; }
  });
  const [addingChild, setAddingChild] = useState(false);
  const [showProfileSwitcher, setShowProfileSwitcher] = useState(false);

  // Derived active profile
  const activeProfile = profiles && profiles.find(p => p.id === activeProfileId) || profiles?.[0] || null;

  // Per-profile week — stored inside profile object
  const week = activeProfile?.week || initWeek();
  const setWeek = (updater) => {
    setProfiles(prev => {
      const next = prev.map(p => p.id === activeProfile.id
        ? { ...p, week: typeof updater === "function" ? updater(p.week) : updater }
        : p);
      saveProfiles(next);
      return next;
    });
  };

  const childName = activeProfile?.name || "";
  const [library, setLibrary]     = useState(PRESET_LIBRARY);
  const [themeId, setThemeId]     = useState(() => activeProfile?.themeId || "lyng");
  const [grayscale, setGrayscale] = useState(false);
  const [showLabels, setShowLabels]   = useState(true);
  const [showRoutines, setShowRoutines] = useState(false);
  const [showTimer, setShowTimer]       = useState(false);
  const [timerSecs, setTimerSecs]       = useState(300); // 5 min default
  const [timerRunning, setTimerRunning] = useState(false);
  const [timerLeft, setTimerLeft]       = useState(300);
  const [showShare, setShowShare]       = useState(false);
  const [tab, setTab]             = useState("week");
  const [focusDay, setFocusDay]   = useState("Man");
  const [bankFor, setBankFor]     = useState(null);
  const [generateFor, setGenerateFor] = useState(null);
  const [editMode, setEditMode]   = useState(false);
  const [dragSrc, setDragSrc]     = useState(null);
  const [dropTarget, setDropTarget] = useState(null);
  const [dayDragSrc, setDayDragSrc]   = useState(null);   // { idx }
  const [dayDropTarget, setDayDropTarget] = useState(null); // idx
  const [dayDropFlash, setDayDropFlash]   = useState(null); // idx of last drop — for flash
  const [editingCard, setEditingCard] = useState(null); // { picto, isNew }
  const [addingToDay, setAddingToDay] = useState(null); // picto to add
  const [selectedCards, setSelectedCards] = useState([]); // library multiselect
  const [libFilter, setLibFilter] = useState("alle"); // "alle"|"mine"
  const [libSearch, setLibSearch] = useState("");
  const [editLabelCard, setEditLabelCard] = useState(null); // { picto, tempLabel }
  const [libGenResult, setLibGenResult] = useState(null); // { emoji, label } from AI
  const [libGenLoading, setLibGenLoading] = useState(false);
  const [showPrint, setShowPrint] = useState(false);
  const [showRoutinePrint, setShowRoutinePrint] = useState(false);
  const [showSymbolSearch, setShowSymbolSearch] = useState(false);
  const [scleraIcons, setScleraIcons] = useState({});
  const [scleraLoading, setScleraLoading] = useState(false);

  const theme    = THEMES.find(t => t.id === themeId);
  const acc      = theme.accent;
  const grad     = theme.grad;
  const activeBg = theme.bg;
  const uiText   = "#1A1410";
  const uiSub    = "#6A5A50";
  const cardRow  = "rgba(255,255,255,0.75)";
  const cardShadow = "0 4px 16px rgba(0,0,0,0.08), 0 1px 4px rgba(0,0,0,0.04)";
  const todayIdx = 2;

  // Library operations
  const saveToLibrary = (picto, original) => {
    if (original) {
      setLibrary(prev => prev.map(p => p.id === original.id ? { ...p, ...picto } : p));
      // Also update any existing week cards that use this id
      setWeek(prev => {
        const next = {};
        DAYS.forEach(d => {
          next[d.short] = (prev[d.short] || []).map(c =>
            c.id === original.id ? { ...c, ...picto } : c
          );
        });
        return next;
      });
    } else {
      const newPicto = { id: uid(), ...picto };
      setLibrary(prev => [newPicto, ...prev]);
    }
  };
  const deleteFromLibrary = (id) => setLibrary(prev => prev.filter(p => p.id !== id));

  // Week operations
  const addCard = (day, p) => setWeek(prev => ({ ...prev, [day]: [...prev[day], makeCard(p)] }));
  const removeCard = (day, u) => setWeek(prev => ({ ...prev, [day]: prev[day].filter(c => c.uid !== u) }));
  const toggleDone = (day, u) => setWeek(prev => ({ ...prev, [day]: prev[day].map(c => c.uid === u ? { ...c, done: !c.done } : c) }));



  // Load inline Sclera SVG icons — no network needed, bundled directly in app
  useEffect(() => {
    setScleraIcons(SCLERA_INLINE);
  }, []);


  // Timer countdown

  useEffect(() => {
    if (!timerRunning) return;
    if (timerLeft <= 0) { setTimerRunning(false); return; }
    const t = setTimeout(() => setTimerLeft(s => s - 1), 1000);
    return () => clearTimeout(t);
  }, [timerRunning, timerLeft]);

  const startTimer = (secs) => { setTimerSecs(secs); setTimerLeft(secs); setTimerRunning(true); setShowTimer(true); };
  const resetTimer = () => { setTimerRunning(false); setTimerLeft(timerSecs); };

  // Share plan — encode week as base64 URL param
  const getShareUrl = () => {
    try {
      const data = JSON.stringify({ week, theme: theme.id });
      const b64 = btoa(unescape(encodeURIComponent(data)));
      return window.location.origin + window.location.pathname + '?plan=' + b64;
    } catch { return window.location.href; }
  };
  const sharePIN = Math.abs(JSON.stringify(week).split('').reduce((a,c)=>((a<<5)-a)+c.charCodeAt(0),0) % 9000 + 1000).toString();

  const onDragStart = (day, idx) => setDragSrc({ day, idx });
  const onDragOver  = (e, day, idx) => { e.preventDefault(); setDropTarget({ day, idx }); };
  const onDragEnd   = () => { setDragSrc(null); setDropTarget(null); };
  const onDrop = (e, tDay, tIdx) => {
    e.preventDefault(); if (!dragSrc) return;
    setWeek(prev => {
      const next = {}; DAYS.forEach(d => { next[d.short] = [...prev[d.short]]; });
      const [moved] = next[dragSrc.day].splice(dragSrc.idx, 1);
      next[tDay].splice(tIdx, 0, moved); return next;
    });
    setDragSrc(null); setDropTarget(null);
  };
  const onDropCol = (e, day) => {
    e.preventDefault(); if (!dragSrc || dragSrc.day === day) { setDragSrc(null); setDropTarget(null); return; }
    setWeek(prev => {
      const next = {}; DAYS.forEach(d => { next[d.short] = [...prev[d.short]]; });
      const [moved] = next[dragSrc.day].splice(dragSrc.idx, 1);
      next[day].push(moved); return next;
    });
    setDragSrc(null); setDropTarget(null);
  };

  // Day view drag handlers
  const onDayDragStart = (idx) => setDayDragSrc(idx);
  const onDayDragEnd   = () => { setDayDragSrc(null); setDayDropTarget(null); };
  const onDayDragOver  = (e, idx) => { e.preventDefault(); setDayDropTarget(idx); };
  const onDayDrop = (e, tIdx) => {
    e.preventDefault();
    if (dayDragSrc === null || dayDragSrc === tIdx) { setDayDragSrc(null); setDayDropTarget(null); return; }
    setWeek(prev => {
      const cards = [...prev[focusDay]];
      const [moved] = cards.splice(dayDragSrc, 1);
      cards.splice(tIdx, 0, moved);
      return { ...prev, [focusDay]: cards };
    });
    setDayDropFlash(tIdx);
    setTimeout(() => setDayDropFlash(null), 350);
    setDayDragSrc(null); setDayDropTarget(null);
  };

  // ── WEEK VIEW ───────────────────────────────────────────────────────────────
  const renderWeek = () => (
    <div style={{ paddingBottom: 100 }}>
      <div className="header-gradient" style={{ background: grad, padding: "24px 20px 20px", borderRadius: "0 0 28px 28px" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <div>
            <div style={{ fontSize: 26, fontWeight: 900, color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", lineHeight: 1, letterSpacing: -0.5 }}>{childName ? `${childName}s Ugeplan` : "Ugeplan"}</div>
            {editMode && <div style={{ fontSize: 12, color: "rgba(255,255,255,0.85)", fontFamily: "'Nunito', sans-serif", fontWeight: 600, marginTop: 2 }}>Træk kort for at flytte dem</div>}
            {/* Profile pills */}
            {profiles && profiles.length > 0 && (
              <div style={{ display: "flex", gap: 6, marginTop: 10, flexWrap: "wrap" }}>
                {profiles.map(p => (
                  <button key={p.id} onClick={() => { setActiveProfileId(p.id); try { localStorage.setItem("ugeplan_active", p.id); } catch {} }} style={{
                    display: "flex", alignItems: "center", gap: 5,
                    background: p.id === activeProfile?.id ? "rgba(255,255,255,0.95)" : "rgba(255,255,255,0.25)",
                    border: "none", borderRadius: 999, padding: "5px 12px 5px 6px",
                    cursor: "pointer", transition: "all 0.22s cubic-bezier(0.34,1.2,0.64,1)",
                    boxShadow: p.id === activeProfile?.id ? "0 3px 10px rgba(0,0,0,0.15)" : "none",
                    transform: p.id === activeProfile?.id ? "scale(1.05)" : "scale(1)",
                  }}>
                    <span style={{ fontSize: 18 }}>{p.avatar || "🦁"}</span>
                    <span style={{ fontSize: 12, fontWeight: 900, fontFamily: "'Nunito', sans-serif", color: p.id === activeProfile?.id ? acc : "#FFFFFF" }}>{p.name}</span>
                  </button>
                ))}
                <button onClick={() => setAddingChild(true)} style={{
                  display: "flex", alignItems: "center", justifyContent: "center",
                  width: 32, height: 32,
                  background: "rgba(255,255,255,0.25)", border: "none", borderRadius: 999,
                  cursor: "pointer", color: "#FFFFFF", fontSize: 20, fontWeight: 700,
                  transition: "all 0.18s",
                }} title="Tilføj barn">+</button>
              </div>
            )}
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={() => setShowLabels(v => !v)} style={{ background: "rgba(255,255,255,0.22)", backdropFilter: "blur(8px)", color: "#FFFFFF", border: "none", borderRadius: 999, padding: "9px 14px", cursor: "pointer", display: "flex", alignItems: "center", gap: 5, fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 13, boxShadow: "0 2px 8px rgba(0,0,0,0.15)", opacity: showLabels ? 1 : 0.6 }} title={showLabels ? "Skjul tekst" : "Vis tekst"}>
              <span style={{ fontSize: 15 }}>{showLabels ? "Aa" : "—"}</span>
            </button>
            <button onClick={() => setShowPrint(true)} style={{ background: "rgba(255,255,255,0.22)", backdropFilter: "blur(8px)", color: "#FFFFFF", border: "none", borderRadius: 999, padding: "9px 16px", cursor: "pointer", display: "flex", alignItems: "center", gap: 6, fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 13, boxShadow: "0 2px 8px rgba(0,0,0,0.15)" }}><Icon name="print" size={16} color="#FFFFFF" />Print</button>
            <button onClick={() => setShowShare(true)} style={{ background: "rgba(255,255,255,0.22)", backdropFilter: "blur(8px)", color: "#FFFFFF", border: "none", borderRadius: 999, padding: "9px 16px", cursor: "pointer", display: "flex", alignItems: "center", gap: 6, fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 13, boxShadow: "0 2px 8px rgba(0,0,0,0.15)" }}><Icon name="share" size={16} color="#FFFFFF" />Del</button>
            <button onClick={() => setEditMode(!editMode)} style={{ background: editMode ? "#FFFFFF" : "rgba(255,255,255,0.22)", backdropFilter: "blur(8px)", color: editMode ? acc : "#FFFFFF", border: "none", borderRadius: 999, padding: "9px 16px", cursor: "pointer", display: "flex", alignItems: "center", gap: 6, fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 13, boxShadow: "0 2px 8px rgba(0,0,0,0.15)" }}><Icon name={editMode ? "check" : "edit"} size={16} color={editMode ? acc : "#FFFFFF"} />{editMode ? "Færdig" : "Rediger"}</button>
          </div>
        </div>
      </div>
      <div style={{ background: activeBg, minHeight: 300, marginTop: -4 }}>
        <div style={{ overflowX: "auto", WebkitOverflowScrolling: "touch" }}>
          <div style={{ display: "flex", minWidth: DAYS.length * 108 + 16, padding: "16px 8px 8px" }}>
            {DAYS.map((day, di) => {
              const cards = week[day.short] || [];
              const isToday = di === todayIdx;
              return (
                <div key={day.short} onDragOver={e => onDragOver(e, day.short, cards.length)} onDrop={e => onDropCol(e, day.short)} style={{ flex: "0 0 100px", width: 100, background: isToday ? "rgba(255,255,255,0.65)" : "transparent", borderRadius: 24, padding: "0 4px 12px", boxShadow: isToday ? "0 8px 24px rgba(0,0,0,0.10)" : "none", border: "none", transition: "box-shadow 0.2s" }}>
                  <div onClick={() => { setFocusDay(day.short); setTab("day"); }} style={{ textAlign: "center", padding: "10px 4px 10px", cursor: "pointer" }}>
                    <div style={{ fontSize: 11, fontWeight: 900, fontFamily: "'Nunito', sans-serif", color: isToday ? acc : "#6A5880", letterSpacing: 0.5, textTransform: "uppercase" }}>{day.short}</div>
                    {isToday
                      ? <div style={{ width: 20, height: 4, background: acc, borderRadius: 99, margin: "4px auto 0", boxShadow: `0 2px 6px ${acc}60` }} />
                      : <div style={{ width: 6, height: 6, background: `${acc}30`, borderRadius: 99, margin: "4px auto 0" }} />
                    }
                  </div>
                  <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 10 }}>
                    {cards.map((card, idx) => (
                      <div key={card.uid} onDragOver={e => { e.stopPropagation(); onDragOver(e, day.short, idx); }} onDrop={e => { e.stopPropagation(); onDrop(e, day.short, idx); }} style={{ position: "relative", width: "100%", display: "flex", justifyContent: "center" }}>
                        {dropTarget?.day === day.short && dropTarget?.idx === idx && <div style={{ position: "absolute", top: -6, left: 4, right: 4, height: 4, background: acc, borderRadius: 99, zIndex: 5 }} />}
                        <PictoCard card={card} small grayscale={grayscale} showLabel={showLabels} dragging={dragSrc?.day === day.short && dragSrc?.idx === idx} onDragStart={() => onDragStart(day.short, idx)} onDragEnd={onDragEnd} accent={acc} scleraUrl={scleraIcons[card.id]} onToggle={() => toggleDone(day.short, card.uid)} onRemove={editMode ? () => removeCard(day.short, card.uid) : null} />
                      </div>
                    ))}
                    <button onClick={() => setBankFor(day.short)} style={{ width: 64, height: cards.length === 0 ? 60 : 40, borderRadius: 18, background: cards.length === 0 ? `${acc}18` : "rgba(255,255,255,0.8)", border: "none", cursor: "pointer", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 2, transition: "all 0.18s cubic-bezier(0.34,1.4,0.64,1)", boxShadow: "0 2px 8px rgba(0,0,0,0.07)" }}>
                      <Icon name="plus" size={cards.length === 0 ? 22 : 14} color={acc} />
                      <span style={{ fontSize: 7, fontWeight: 900, color: acc, fontFamily: "'Nunito', sans-serif", lineHeight: 1 }}>Tilføj</span>
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );

  // ── DAY VIEW ────────────────────────────────────────────────────────────────
  const renderDay = () => {
    const day   = DAYS.find(d => d.short === focusDay);
    const cards = week[focusDay] || [];
    const done  = cards.filter(c => c.done).length;
    return (
      <div style={{ paddingBottom: 100 }}>
        <div className="header-gradient" style={{ background: grad, padding: "18px 20px 20px", borderRadius: "0 0 28px 28px" }}>
          {/* Day selector strip */}
          <div style={{ display: "flex", gap: 5, marginBottom: 14, overflowX: "auto", paddingBottom: 2 }}>
            {DAYS.map(d => {
              const dayCards = week[d.short] || [];
              const dayDone = dayCards.filter(c => c.done).length;
              const isActive = d.short === focusDay;
              return (
                <button key={d.short} onClick={() => setFocusDay(d.short)} style={{
                  flexShrink: 0, padding: "7px 12px",
                  background: isActive ? "#FFFFFF" : "rgba(255,255,255,0.2)",
                  color: isActive ? acc : "#FFFFFF",
                  borderRadius: 999, border: "none",
                  cursor: "pointer", fontSize: 11, fontWeight: 900,
                  fontFamily: "'Nunito', sans-serif",
                  boxShadow: isActive ? "0 4px 12px rgba(0,0,0,0.15)" : "none",
                  display: "flex", flexDirection: "column", alignItems: "center", gap: 2,
                }}>
                  <span>{d.short}</span>
                  {dayCards.length > 0 && (
                    <span style={{ fontSize: 8, fontWeight: 700, opacity: isActive ? 0.7 : 0.6 }}>
                      {dayDone}/{dayCards.length}
                    </span>
                  )}
                </button>
              );
            })}
          </div>
          {/* Title row */}
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 10 }}>
            <div style={{ fontSize: 28, fontWeight: 900, color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", letterSpacing: -0.5 }}>{day.full}</div>
            <div style={{ display: "flex", gap: 8 }}>
              <button onClick={() => setShowPrint(true)} style={{ background: "rgba(255,255,255,0.22)", backdropFilter: "blur(8px)", color: "#FFFFFF", border: "none", borderRadius: 999, padding: "8px 14px", cursor: "pointer", display: "flex", alignItems: "center", gap: 5, fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 12, flexShrink: 0, boxShadow: "0 2px 8px rgba(0,0,0,0.15)" }}><Icon name="print" size={14} color="#FFFFFF" />Print</button>
              <button onClick={() => setShowShare(true)} style={{ background: "rgba(255,255,255,0.22)", backdropFilter: "blur(8px)", color: "#FFFFFF", border: "none", borderRadius: 999, padding: "8px 14px", cursor: "pointer", display: "flex", alignItems: "center", gap: 5, fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 12, flexShrink: 0, boxShadow: "0 2px 8px rgba(0,0,0,0.15)" }}><Icon name="share" size={14} color="#FFFFFF" />Del</button>
              <button onClick={() => setEditMode(!editMode)} style={{ background: editMode ? "#FFFFFF" : "rgba(255,255,255,0.22)", backdropFilter: "blur(8px)", color: editMode ? acc : "#FFFFFF", border: "none", borderRadius: 999, padding: "8px 14px", cursor: "pointer", display: "flex", alignItems: "center", gap: 5, fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 12, flexShrink: 0, boxShadow: "0 2px 8px rgba(0,0,0,0.15)" }}><Icon name={editMode ? "check" : "edit"} size={14} color={editMode ? acc : "#FFFFFF"} />{editMode ? "Færdig" : "Rediger"}</button>
            </div>
          </div>
          {/* Progress bar */}
          <div style={{ height: 10, background: "rgba(255,255,255,0.25)", borderRadius: 999, overflow: "hidden", marginTop: 2 }}>
            <div className="progress-glow" style={{ height: "100%", background: "#FFFFFF", borderRadius: 999, width: `${cards.length ? done/cards.length*100 : 0}%`, transition: "width 0.6s cubic-bezier(0.34,1.1,0.64,1)" }} />
          </div>
          <div style={{ fontSize: 11, color: "rgba(255,255,255,0.85)", fontFamily: "'Nunito', sans-serif", fontWeight: 700, marginTop: 5 }}>{done} af {cards.length} aktiviteter klaret</div>
        </div>
        <div style={{ background: activeBg, padding: "20px 0 20px", minHeight: 200 }}>
          {cards.length === 0 && (
            <div style={{ textAlign: "center", padding: "40px 20px 20px", color: "#8A7A90", fontFamily: "'Nunito', sans-serif" }}>
              <div style={{ fontSize: 13, fontWeight: 700, marginBottom: 6 }}>Ingen aktiviteter endnu</div>
              <div style={{ fontSize: 12, opacity: 0.7 }}>Tryk + for at tilføje</div>
            </div>
          )}
          <div style={{ display: "flex", flexDirection: "column", gap: 10, padding: cards.length === 0 ? "0 18px 8px" : "16px 18px 8px" }}>
              {cards.map((card, idx) => {
                const isDragging = dayDragSrc === idx;
                const isDropTarget = dayDropTarget === idx && dayDragSrc !== null && dayDragSrc !== idx;
                const isFlashing = dayDropFlash === idx;
                return (
                  <div key={card.uid}
                    draggable
                    onDragStart={() => onDayDragStart(idx)}
                    onDragEnd={onDayDragEnd}
                    onDragOver={e => onDayDragOver(e, idx)}
                    onDrop={e => onDayDrop(e, idx)}
                    className="card-row"
                    style={{
                      display: "flex", alignItems: "center", gap: 14,
                      background: isFlashing ? `${acc}28` : card.done ? "rgba(255,255,255,0.35)" : cardRow,
                      borderRadius: 20, padding: "10px 14px",
                      opacity: isDragging ? 0.3 : card.done ? 0.65 : 1,
                      transform: isDropTarget ? "scale(1.02)" : "scale(1)",
                      boxShadow: isDropTarget ? `0 0 0 2.5px ${acc}` : isFlashing ? `0 0 0 2.5px ${acc}80` : "none",
                      transition: "opacity 0.15s, transform 0.12s, box-shadow 0.12s, background 0.25s",
                      cursor: "grab",
                    }}>
                    <PictoCard card={card} grayscale={grayscale} accent={acc} scleraUrl={scleraIcons[card.id]} onToggle={() => toggleDone(focusDay, card.uid)} onRemove={editMode ? () => removeCard(focusDay, card.uid) : null} dragging={isDragging} onDragStart={() => onDayDragStart(idx)} onDragEnd={onDayDragEnd} />
                    <span style={{ flex: 1, fontSize: 18, fontWeight: 800, color: card.done ? "#9A9090" : "#1A1410", fontFamily: "'Nunito', sans-serif", textDecoration: card.done ? "line-through" : "none", transition: "color 0.2s", letterSpacing: -0.2 }}>{card.label}</span>
                    {card.done && (
                      <div style={{
                        display: "flex", alignItems: "center", gap: 6,
                        background: acc,
                        borderRadius: 999, padding: "6px 14px",
                        boxShadow: `0 3px 12px ${acc}60`,
                        flexShrink: 0,
                        animation: "doneOverlay 0.35s cubic-bezier(0.34,1.56,0.64,1)",
                      }}>
                        <Icon name="check" size={16} color="#FFFFFF" />
                        <span style={{ fontSize: 12, fontWeight: 900, color: "#FFFFFF", fontFamily: "'Nunito', sans-serif" }}>Klaret!</span>
                      </div>
                    )}
                  </div>
                );
              })}
              {/* Add activity — compact row */}
              <button onClick={() => setBankFor(focusDay)} style={{
                display: "flex", alignItems: "center", gap: 14,
                background: "#FFFFFF", border: "none",
                borderRadius: 24, padding: "14px 20px", cursor: "pointer",
                color: acc, fontFamily: "'Nunito', sans-serif", fontWeight: 900, fontSize: 16,
                marginTop: 8, boxShadow: "0 4px 16px rgba(0,0,0,0.10)",
              }}>
                <div style={{ width: 42, height: 42, borderRadius: 14, background: grad, display: "flex", alignItems: "center", justifyContent: "center", boxShadow: `0 4px 10px ${acc}50` }}>
                  <Icon name="plus" size={22} color="#FFFFFF" />
                </div>
                <span>Tilføj aktivitet</span>
              </button>
          </div>

        </div>
      </div>
    );
  };

  // ── LIBRARY VIEW ────────────────────────────────────────────────────────────
  const generateLibCard = async (query) => {
    setLibGenLoading(true);
    setLibGenResult(null);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 800,
          messages: [{
            role: "user",
            content: `Tegn et simpelt SVG piktogram af "${query}" til børn (alder 4-10).

Regler:
- viewBox="0 0 100 100"
- Maks 12 SVG-elementer (rect, circle, ellipse, path, polygon, line)
- Tykke streger (stroke-width 4-7), stroke-linecap="round", stroke-linejoin="round"
- Brug disse to farver: baggrundsfarve="${theme.bg}" og accentfarve="${acc}"
- Baggrund: <rect width="100" height="100" fill="${theme.bg}"/>
- Figuren tegnes med fill="${acc}" og evt. stroke="${acc}"
- Genkendelig silhouet, ikke for detaljeret, barnlig og glad stil
- Svar KUN med JSON (ingen markdown):
{"label":"${query}","svg":"<svg viewBox=\"0 0 100 100\" xmlns=\"http://www.w3.org/2000/svg\">...</svg>"}`
          }]
        })
      });
      const data = await res.json();
      const text = data.content?.[0]?.text || "";
      // Extract JSON — handle multiline svg
      const match = text.match(/\{[\s\S]*"svg"\s*:\s*"[\s\S]*?"\s*\}/);
      if (match) {
        try {
          const parsed = JSON.parse(match[0]);
          setLibGenResult({ label: parsed.label, svg: parsed.svg, emoji: "🖼️" });
        } catch(e) {
          // fallback: try to extract svg directly
          const svgMatch = text.match(/<svg[\s\S]*?<\/svg>/);
          if (svgMatch) setLibGenResult({ label: query, svg: svgMatch[0], emoji: "🖼️" });
        }
      }
    } catch(e) {}
    setLibGenLoading(false);
  };

  const saveLabel = (picto, newLabel) => {
    if (!newLabel.trim()) return;
    setLibrary(prev => prev.map(p => p.id === picto.id ? { ...p, label: newLabel.trim() } : p));
    setEditLabelCard(null);
  };

  const renderLibrary = () => {
    const presetIds = new Set(PRESET_LIBRARY.map(p => p.id));
    const myCards   = library.filter(p => !presetIds.has(p.id));
    const standard  = library.filter(p => presetIds.has(p.id));
    const baseCards = libFilter === "mine" ? myCards : library;
    const showCards = libSearch.trim()
      ? baseCards.filter(p => { const q = libSearch.toLowerCase(); return p.label.toLowerCase().includes(q) || (p.tags || []).some(t => t.toLowerCase().includes(q)); })
      : baseCards;

    return (
      <div style={{ paddingBottom: 100 }}>
        {/* Header */}
        <div className="header-gradient" style={{ background: grad, padding: "22px 20px 20px", borderRadius: "0 0 28px 28px" }}>
          <div style={{ fontSize: 24, fontWeight: 900, color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", lineHeight: 1, marginBottom: 2, letterSpacing: -0.5 }}>
            Bibliotek
          </div>
          <div style={{ fontSize: 13, color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", fontWeight: 600 }}>
            {library.length} kort · {myCards.length} egne
          </div>
        </div>

        <div style={{ background: activeBg, padding: "16px 18px 24px" }}>

          {/* Add symbol button */}
          <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
            
            <button onClick={() => setEditingCard({ picto: { emoji: "⭐", label: "" }, isNew: true })}
              title="Lav eget kort"
              style={{
                width: 54, height: 54, background: "#FFFFFF",
                border: "none", borderRadius: 999, color: acc,
                cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center",
                boxShadow: "0 4px 16px rgba(0,0,0,0.10)", flexShrink: 0,
              }}>
              <Icon name="edit" size={20} color={acc} />
            </button>
          </div>

          {/* Filter tabs */}
          <div style={{ display: "flex", background: "rgba(255,255,255,0.7)", borderRadius: 999, padding: 4, marginBottom: 16, boxShadow: "0 2px 8px rgba(0,0,0,0.06)" }}>
            {[["alle", `Alle (${library.length})`], ["mine", `Mine (${myCards.length})`]].map(([id, lbl]) => (
              <button key={id} onClick={() => setLibFilter(id)} style={{
                flex: 1, padding: "10px 0", borderRadius: 999,
                background: libFilter === id ? acc : "transparent",
                color: libFilter === id ? "#FFFFFF" : "#6A5A50",
                border: "none", cursor: "pointer",
                fontFamily: "'Nunito', sans-serif", fontWeight: 900, fontSize: 13,
                boxShadow: libFilter === id ? `0 4px 10px ${acc}40` : "none",
                transition: "all 0.2s cubic-bezier(0.34,1.2,0.64,1)",
              }}>{lbl}</button>
            ))}
          </div>

          {/* Search bar */}
          <div style={{
            display: "flex", alignItems: "center", gap: 10,
            background: "rgba(255,255,255,0.85)", borderRadius: 16,
            padding: "10px 16px", marginBottom: 16,
            boxShadow: "0 2px 8px rgba(0,0,0,0.06)",
          }}>
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#6A5A50" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/>
            </svg>
            <input
              value={libSearch}
              onChange={e => { setLibSearch(e.target.value); setLibGenResult(null); }}
              placeholder="Søg i bibliotek…"
              style={{
                flex: 1, border: "none", outline: "none", background: "transparent",
                fontSize: 14, fontWeight: 600, color: "#1A0840",
                fontFamily: "'Nunito', sans-serif",
              }}
            />
            {libSearch && (
              <button onClick={() => setLibSearch("")} style={{
                background: "none", border: "none", cursor: "pointer", padding: 2,
                color: "#6A5A50", display: "flex", alignItems: "center",
              }}>
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
                  <path d="M18 6 6 18M6 6l12 12"/>
                </svg>
              </button>
            )}
          </div>

          {/* Empty search state — offer AI generation */}
          {libSearch && showCards.length === 0 && (
            <div style={{ textAlign: "center", padding: "24px 8px 16px", fontFamily: "'Nunito', sans-serif" }}>
              <div style={{ fontSize: 36, marginBottom: 8 }}>🔍</div>
              <div style={{ fontSize: 15, fontWeight: 800, color: "#1A0840", marginBottom: 4 }}>
                Ingen kort for "{libSearch}"
              </div>
              <div style={{ fontSize: 13, color: "#6A5A50", marginBottom: 20 }}>
                Vil du oprette et nyt kort?
              </div>

              {/* Generate button */}
              {!libGenResult && (
                <button
                  onClick={() => generateLibCard(libSearch)}
                  disabled={libGenLoading}
                  style={{
                    background: libGenLoading ? "#EEE" : acc,
                    color: libGenLoading ? "#AAA" : "#FFF",
                    border: "none", borderRadius: 999,
                    padding: "13px 28px", fontSize: 14, fontWeight: 900,
                    cursor: libGenLoading ? "default" : "pointer",
                    display: "inline-flex", alignItems: "center", gap: 10,
                    boxShadow: libGenLoading ? "none" : `0 4px 16px ${acc}50`,
                    fontFamily: "'Nunito', sans-serif",
                  }}>
                  {libGenLoading
                    ? <><div style={{ width: 18, height: 18, borderRadius: "50%", border: `3px solid #CCC`, borderTopColor: "#888", animation: "spin 0.8s linear infinite" }} /> Tegner ikon…</>
                    : <><Icon name="ai" size={18} color="#FFF" /> Tegn "{libSearch}"</>
                  }
                </button>
              )}

              {/* Result card */}
              {libGenResult && (
                <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 16 }}>
                  <div style={{
                    width: 90, height: 100, background: grayscale ? "#000000" : (libGenResult.svg ? theme.bg : CARD_BG),
                    borderRadius: 28,
                    display: "flex", alignItems: "center", justifyContent: "center",
                    boxShadow: "0 4px 20px rgba(0,0,0,0.12)",
                    fontSize: 46,
                    overflow: "hidden",
                  }}>
                    {libGenResult.svg
                      ? <div style={{ lineHeight: 0, filter: grayscale ? "grayscale(1) brightness(3)" : "none" }} dangerouslySetInnerHTML={{ __html: libGenResult.svg.replace(/<svg/, '<svg width="90" height="100"') }} />
                      : <span style={{ filter: grayscale ? "grayscale(1) brightness(3)" : "none" }}>{libGenResult.emoji}</span>
                    }
                  </div>
                  <div style={{ fontSize: 14, fontWeight: 800, color: "#1A0840" }}>{libGenResult.label}</div>
                  <div style={{ display: "flex", gap: 10 }}>
                    <button
                      onClick={() => {
                        const newCard = { id: "custom_" + Date.now(), emoji: libGenResult.svg ? "🖼️" : libGenResult.emoji, label: libGenResult.label, svg: libGenResult.svg || null };
                        setLibrary(prev => [...prev, newCard]);
                        setLibSearch("");
                        setLibGenResult(null);
                      }}
                      style={{
                        background: acc, color: "#FFF", border: "none", borderRadius: 999,
                        padding: "11px 22px", fontSize: 13, fontWeight: 900, cursor: "pointer",
                        display: "flex", alignItems: "center", gap: 8,
                        boxShadow: `0 4px 14px ${acc}50`,
                        fontFamily: "'Nunito', sans-serif",
                      }}>
                      <Icon name="plus" size={16} color="#FFF" /> Tilføj til bibliotek
                    </button>
                    <button
                      onClick={() => generateLibCard(libSearch)}
                      style={{
                        background: "rgba(0,0,0,0.06)", color: "#1A0840", border: "none", borderRadius: 999,
                        padding: "11px 18px", fontSize: 13, fontWeight: 800, cursor: "pointer",
                        fontFamily: "'Nunito', sans-serif",
                      }}>
                      Prøv igen
                    </button>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Empty state for "mine" */}
          {libFilter === "mine" && myCards.length === 0 && (
            <div style={{ textAlign: "center", padding: "32px 0", color: "#6A5A50", fontFamily: "'Nunito', sans-serif" }}>
              <div style={{ fontSize: 48, marginBottom: 12 }}>🌱</div>
              <div style={{ fontSize: 16, fontWeight: 800, marginBottom: 6 }}>Ingen egne kort endnu</div>
              <div style={{ fontSize: 13 }}>Tryk "Nyt kort" for at lave dit første</div>
            </div>
          )}

          {/* Card grid */}
          {showCards.length > 0 && (
            <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 16, paddingBottom: selectedCards.length > 0 ? 100 : 0 }}>
              {showCards.map(picto => {
                const cardBg = CARD_BG;
                const isCustom = !presetIds.has(picto.id);
                const isSelected = selectedCards.includes(picto.id);
                return (
                  <div key={picto.id} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6 }}>
                    <div style={{ position: "relative" }}>
                      <div
                        onClick={() => {
                          if (editMode) return;
                          setSelectedCards(prev =>
                            prev.includes(picto.id) ? prev.filter(id => id !== picto.id) : [...prev, picto.id]
                          );
                        }}
                        onContextMenu={e => { e.preventDefault(); setEditLabelCard({ picto, tempLabel: picto.label }); }}
                        onPointerDown={(() => { let t; return e => { t = setTimeout(() => setEditLabelCard({ picto, tempLabel: picto.label }), 600); e.currentTarget._lpt = t; }; })()}
                        onPointerUp={e => clearTimeout(e.currentTarget._lpt)}
                        onPointerLeave={e => clearTimeout(e.currentTarget._lpt)}
                        style={{
                          width: 80, height: 88, background: grayscale ? "#000000" : cardBg, borderRadius: 26,
                          display: "flex", alignItems: "center", justifyContent: "center",
                          cursor: "pointer", position: "relative",
                          border: isSelected ? `3px solid ${acc}` : "3px solid transparent",
                          boxShadow: isSelected ? `0 0 0 4px ${acc}30, 0 4px 14px rgba(0,0,0,0.10)` : "0 4px 14px rgba(0,0,0,0.10), 0 1px 3px rgba(0,0,0,0.06)",
                          transform: isSelected ? "scale(1.06)" : "scale(1)",
                          transition: "all 0.18s cubic-bezier(0.34,1.56,0.64,1)",
                        }}
                      >
                        {!isSelected && <div style={{ position: "absolute", top: 9, right: 11, width: 9, height: 9, borderRadius: "50%", background: "rgba(255,255,255,0.65)" }} />}
                        {isSelected && (
                          <div style={{ position: "absolute", top: -10, right: -10, width: 24, height: 24, borderRadius: "50%", background: acc, border: "2px solid #FFFFFF", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 5, boxShadow: `0 2px 8px ${acc}60` }}>
                            <Icon name="check" size={13} color="#FFFFFF" />
                          </div>
                        )}
                        {grayscale
                          ? scleraLoading
                            ? <div style={{ width: 42, height: 42, borderRadius: 8, background: "rgba(255,255,255,0.4)", animation: "pulse 1.2s ease-in-out infinite" }} />
                            : (scleraIcons[picto.id] || picto.sclera_url)
                              ? <img src={scleraIcons[picto.id] || picto.sclera_url} alt={picto.label} style={{ width: 42, height: 42, objectFit: "contain" }} />
                              : <span style={{ fontSize: 34, filter: "grayscale(1) brightness(3)" }}>{picto.emoji}</span>
                          : <span style={{ fontSize: 34 }}>{picto.emoji}</span>}
                      </div>
                      {editMode && <>
                        <button onClick={() => setEditingCard({ picto, isNew: false })} style={{ position: "absolute", top: -8, left: -8, width: 28, height: 28, borderRadius: "50%", background: "#4A18A0", border: "2px solid #FFFFFF", color: "#FFFFFF", fontSize: 12, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 900, zIndex: 10 }}><Icon name="edit" size={13} color="#FFFFFF" /></button>
                        {isCustom && (
                          <button onClick={() => deleteFromLibrary(picto.id)} style={{ position: "absolute", top: -8, right: -8, width: 28, height: 28, borderRadius: "50%", background: "#C41830", border: "2px solid #FFFFFF", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 10 }}><Icon name="close" size={13} color="#FFFFFF" /></button>
                        )}
                      </>}
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: 3, maxWidth: 90, cursor: "default" }}>
                      <span style={{ fontSize: 11, fontWeight: 800, color: isSelected ? acc : "#1A1410", fontFamily: "'Nunito', sans-serif", textAlign: "center", lineHeight: 1.2, transition: "color 0.15s" }}>{picto.label}</span>
                      <button onClick={e => { e.stopPropagation(); setEditLabelCard({ picto, tempLabel: picto.label }); }} title="Rediger navn" style={{ flexShrink: 0, background: "none", border: "none", padding: 1, cursor: "pointer", opacity: 0.4, display: "flex", alignItems: "center" }}>
                        <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="#1A1410" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4z"/></svg>
                      </button>
                    </div>
                    {isCustom && !isSelected && <span style={{ fontSize: 9, color: acc, fontFamily: "'Nunito', sans-serif", fontWeight: 700, background: `${acc}22`, borderRadius: 6, padding: "2px 6px" }}>Mit kort</span>}
                  </div>
                );
              })}
            </div>
          )}

          {/* Floating add bar — appears when cards are selected */}
          {selectedCards.length > 0 && (
            <div style={{ position: "fixed", bottom: 90, left: "50%", transform: "translateX(-50%)", width: "calc(100% - 32px)", maxWidth: 398, zIndex: 300, animation: "slideUp 0.25s cubic-bezier(0.34,1.4,0.64,1)" }}>
              <div style={{ background: "#FFFFFF", borderRadius: 24, padding: "14px 16px", boxShadow: "0 8px 32px rgba(26,8,64,0.22), 0 2px 8px rgba(0,0,0,0.1)", display: "flex", alignItems: "center", gap: 12 }}>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 13, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif" }}>
                    {selectedCards.length} kort valgt
                  </div>
                  <div style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", marginTop: 1 }}>Vælg hvilken dag</div>
                  <div style={{ display: "flex", gap: 6, marginTop: 8, flexWrap: "wrap" }}>
                    {DAYS.map(d => (
                      <button key={d.short} onClick={() => {
                        const pictos = showCards.filter(p => selectedCards.includes(p.id));
                        pictos.forEach(p => addCard(d.short, p));
                        setSelectedCards([]);
                      }} style={{ padding: "6px 10px", borderRadius: 999, background: acc, border: "none", color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 11, cursor: "pointer", boxShadow: `0 2px 8px ${acc}40` }}>
                        {d.short}
                      </button>
                    ))}
                  </div>
                </div>
                <button onClick={() => setSelectedCards([])} style={{ width: 36, height: 36, borderRadius: "50%", background: "#F0EBF8", border: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                  <Icon name="close" size={16} color="#6A5880" />
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  };


  // ── ROUTINES VIEW ───────────────────────────────────────────────────────────
  const renderRoutines = () => (
    <div style={{ paddingBottom: 100 }}>
      <div className="header-gradient" style={{ background: grad, padding: "22px 20px 20px", borderRadius: "0 0 28px 28px" }}>
        <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between" }}>
          <div>
            <div style={{ fontSize: 24, fontWeight: 900, color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", letterSpacing: -0.5 }}>Rutiner</div>
            <div style={{ fontSize: 13, color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", fontWeight: 600, marginTop: 2 }}>Skabeloner og timer til hverdagen</div>
          </div>
          <button onClick={() => setShowRoutinePrint(true)} style={{
            background: "rgba(255,255,255,0.22)", backdropFilter: "blur(8px)",
            border: "none", borderRadius: 999, padding: "9px 16px",
            color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 13,
            cursor: "pointer", display: "flex", alignItems: "center", gap: 6,
            boxShadow: "0 2px 8px rgba(0,0,0,0.15)",
          }}>
            <Icon name="print" size={16} color="#FFFFFF" /> Print strimler
          </button>
        </div>
      </div>
      <div style={{ background: activeBg, padding: "20px 18px 24px" }}>

        {/* Routine templates */}
        <div style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", fontWeight: 800, letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 14 }}>Rutineskabeloner</div>
        <div style={{ display: "flex", flexDirection: "column", gap: 12, marginBottom: 28 }}>
          {ROUTINE_TEMPLATES.map(r => (
            <div key={r.id} onClick={() => setShowRoutines(true)} style={{ display: "flex", alignItems: "center", gap: 16, padding: "16px 18px", background: "#FFFFFF", borderRadius: 20, cursor: "pointer", boxShadow: "0 3px 12px rgba(0,0,0,0.08)" }}>
              <div style={{ width: 52, height: 52, borderRadius: 16, background: r.color + "22", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 26, flexShrink: 0 }}>{r.emoji}</div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 16, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif" }}>{r.label}</div>
                <div style={{ fontSize: 12, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", marginTop: 1 }}>{r.cards.length} aktiviteter · {r.desc}</div>
              </div>
              <span style={{ fontSize: 20, color: "#C0B8D0" }}>›</span>
            </div>
          ))}
        </div>

        {/* Timer */}
        <div style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", fontWeight: 800, letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 14 }}>Time Timer</div>
        <div onClick={() => setShowTimer(true)} style={{ display: "flex", alignItems: "center", gap: 16, padding: "18px 20px", background: "#FFFFFF", borderRadius: 20, cursor: "pointer", boxShadow: "0 3px 12px rgba(0,0,0,0.08)" }}>
          {/* Mini timer preview */}
          <div style={{ width: 56, height: 56, borderRadius: "50%", background: timerRunning ? acc + "22" : "#F0EBF8", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, position: "relative" }}>
            <svg width="56" height="56" style={{ position: "absolute", transform: "rotate(-90deg)" }}>
              <circle cx="28" cy="28" r="22" fill="none" stroke="#E0D8F0" strokeWidth="4" />
              <circle cx="28" cy="28" r="22" fill="none" stroke={timerLeft === 0 ? "#22C55E" : acc} strokeWidth="4"
                strokeDasharray={`${(timerLeft / timerSecs) * 138} 138`} strokeLinecap="round" />
            </svg>
            <span style={{ fontSize: 11, fontWeight: 900, color: acc, fontFamily: "'Nunito', sans-serif", zIndex: 1 }}>
              {timerRunning ? `${Math.floor(timerLeft/60)}:${String(timerLeft%60).padStart(2,"0")}` : "⏱"}
            </span>
          </div>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 16, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif" }}>
              {timerRunning ? "Timer kører..." : timerLeft === 0 ? "Tid! 🎉" : "Start timer"}
            </div>
            <div style={{ fontSize: 12, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", marginTop: 1 }}>
              {timerRunning ? `${Math.floor(timerLeft/60)} min tilbage` : "Vælg 5–30 minutter"}
            </div>
          </div>
          <span style={{ fontSize: 20, color: "#C0B8D0" }}>›</span>
        </div>

        {/* Share */}
        <div style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", fontWeight: 800, letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 14, marginTop: 28 }}>Del med partner</div>
        <div onClick={() => setShowShare(true)} style={{ display: "flex", alignItems: "center", gap: 16, padding: "18px 20px", background: "#FFFFFF", borderRadius: 20, cursor: "pointer", boxShadow: "0 3px 12px rgba(0,0,0,0.08)" }}>
          <div style={{ width: 56, height: 56, borderRadius: 16, background: "#F0EBF8", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 26, flexShrink: 0 }}>👥</div>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 16, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif" }}>Del ugeplanen</div>
            <div style={{ fontSize: 12, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", marginTop: 1 }}>Via delelink eller PIN-kode til din partner</div>
          </div>
          <span style={{ fontSize: 20, color: "#C0B8D0" }}>›</span>
        </div>

      </div>
    </div>
  );


  // ── SETTINGS VIEW ───────────────────────────────────────────────────────────
  const renderTheme = () => (
    <div style={{ paddingBottom: 100 }}>
      <div className="header-gradient" style={{ background: grad, padding: "22px 20px 20px", borderRadius: "0 0 28px 28px" }}>
        <div style={{ fontSize: 24, fontWeight: 900, color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", letterSpacing: -0.5 }}>Udseende</div>
        <div style={{ fontSize: 13, color: "#FFFFFF", fontFamily: "'Nunito', sans-serif", fontWeight: 600, marginTop: 2 }}>Tilpas til barnets tryghedszone</div>
      </div>
      <div style={{ background: activeBg, padding: "16px 18px 24px" }}>

        {/* Background theme — exactly 5 choices */}
        <div style={{ background: "#FFFFFF", borderRadius: 24, padding: "20px", marginBottom: 14, boxShadow: "0 4px 16px rgba(0,0,0,0.07)" }}>
          <div style={{ fontSize: 14, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif", marginBottom: 4 }}>Baggrundsfarve</div>
          <div style={{ fontSize: 12, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", marginBottom: 18 }}>Vælg det tema der føles roligst</div>
          <div style={{ display: "flex", gap: 12, justifyContent: "space-between" }}>
            {THEMES.map(th => (
              <button key={th.id} onClick={() => handleSetThemeId(th.id)} style={{
                flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 6,
                background: "transparent", border: "none", cursor: "pointer", padding: 0,
              }}>
                <div style={{
                  width: "100%", aspectRatio: "1", borderRadius: 18,
                  background: th.bg,
                  border: th.id === themeId ? `3.5px solid ${th.accent}` : "3px solid rgba(0,0,0,0.06)",
                  display: "flex", alignItems: "center", justifyContent: "center",
                  transform: th.id === themeId ? "scale(1.1)" : "scale(1)",
                  transition: "transform 0.18s, box-shadow 0.18s",
                  boxShadow: th.id === themeId ? `0 6px 16px ${th.accent}40` : "none",
                  overflow: "hidden", position: "relative",
                }}>
                  <span style={{ fontSize: 32, lineHeight: 1 }}>{th.icon}</span>
                  {th.id === themeId && <div style={{ position: "absolute", bottom: 5, right: 5, width: 16, height: 16, borderRadius: "50%", background: th.accent, display: "flex", alignItems: "center", justifyContent: "center", boxShadow: "0 2px 6px rgba(0,0,0,0.2)" }}><Icon name="check" size={10} color="#FFFFFF" /></div>}
                </div>
                <span style={{
                  fontSize: 11, fontWeight: 900,
                  color: th.id === themeId ? th.accent : "#6A5A50",
                  fontFamily: "'Nunito', sans-serif",
                }}>{th.label}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Pictogram mode — color vs high-contrast B&W */}
        <div style={{ background: "#FFFFFF", borderRadius: 24, padding: "20px", boxShadow: "0 4px 16px rgba(0,0,0,0.07)" }}>
          <div style={{ fontSize: 14, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif", marginBottom: 4 }}>Piktogramtilstand</div>
          <div style={{ fontSize: 12, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", marginBottom: 16 }}>Farver eller høj sort/hvid kontrast</div>
          <div style={{ display: "flex", gap: 12, marginBottom: 18 }}>
            <button onClick={() => setGrayscale(false)} style={{
              flex: 1, padding: "16px 0", borderRadius: 16, cursor: "pointer",
              background: !grayscale ? grad : "rgba(0,0,0,0.04)",
              color: !grayscale ? "#FFFFFF" : "#6A5A50",
              border: "none",
              boxShadow: !grayscale ? `0 4px 12px ${acc}50` : "none",
              fontFamily: "'Nunito', sans-serif", fontWeight: 900, fontSize: 14,
              display: "flex", flexDirection: "column", alignItems: "center", gap: 10,
            }}>
              <div style={{ display: "flex", gap: 6 }}>
                {["#F5922A","#E8657A","#4BAD6A","#F5C842"].map(c => (
                  <div key={c} style={{ width: 18, height: 18, borderRadius: 6, background: c }} />
                ))}
              </div>
              Farverig
            </button>
            <button onClick={() => setGrayscale(true)} style={{
              flex: 1, padding: "16px 0", borderRadius: 16, cursor: "pointer",
              background: grayscale ? "#000000" : "rgba(0,0,0,0.04)",
              color: grayscale ? "#FFFFFF" : "#6A5A50",
              border: "none",
              boxShadow: grayscale ? "0 4px 12px rgba(0,0,0,0.3)" : "none",
              fontFamily: "'Nunito', sans-serif", fontWeight: 900, fontSize: 14,
              display: "flex", flexDirection: "column", alignItems: "center", gap: 10,
            }}>
              <div style={{ display: "flex", gap: 6 }}>
                {["#FFFFFF","#FFFFFF","#FFFFFF","#FFFFFF"].map((c,i) => (
                  <div key={i} style={{ width: 18, height: 18, borderRadius: 6, background: c, border: "2px solid #1A1410" }} />
                ))}
              </div>
              Sort/hvid
            </button>
          </div>

          {/* Live preview */}
          <div style={{ background: activeBg, borderRadius: 14, padding: "14px 10px" }}>
            <div style={{ fontSize: 11, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", fontWeight: 700, letterSpacing: 1, textTransform: "uppercase", marginBottom: 12, textAlign: "center" }}>
              Forhåndsvisning
            </div>
            <div style={{ display: "flex", gap: 10, justifyContent: "center" }}>
              {[
                { id: "hjem",     emoji: "🏠", label: "Hjemme", tags: ["hus", "hjemme", "bolig"] },
                { id: "skole",    emoji: "🎒", label: "Skole", tags: ["skoledag", "undervisning", "klasse", "SFO"] },
                { id: "leg",      emoji: "🧸", label: "Leg", tags: ["lege", "fri leg", "fantasileg", "rollespil"] },
                { id: "sengetid", emoji: "🌙", label: "Sengetid", tags: ["godnat", "nat", "sove", "sovetid"] },
              ].map((item) => {
                const bg = grayscale ? "#000000" : CARD_BG;
                return (
                  <div key={item.id} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 5 }}>
                    <div style={{
                      width: 56, height: 62, borderRadius: 18,
                      background: bg,
                      display: "flex", alignItems: "center", justifyContent: "center",
                      position: "relative",
                      boxShadow: "0 2px 8px rgba(0,0,0,0.10)",
                    }}>
                      {!grayscale && <div style={{ position: "absolute", top: 7, right: 9, width: 8, height: 8, borderRadius: "50%", background: "rgba(255,255,255,0.65)" }} />}
                      {grayscale && scleraIcons[item.id]
                        ? <img src={scleraIcons[item.id]} alt={item.label} style={{ width: 46, height: 46, objectFit: "contain" }} />
                        : <span style={{ fontSize: 26, filter: grayscale ? "grayscale(1) brightness(3)" : "none" }}>{item.emoji}</span>
                      }
                    </div>
                    <span style={{ fontSize: 9, fontWeight: 800, color: grayscale ? "#6A5A50" : "#6A5A50", fontFamily: "'Nunito', sans-serif" }}>{item.label}</span>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
        {/* Profile management */}
        <div style={{ background: "#FFFFFF", borderRadius: 24, padding: "20px", marginTop: 14, boxShadow: "0 4px 16px rgba(0,0,0,0.07)" }}>
          <div style={{ fontSize: 14, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif", marginBottom: 4 }}>Børns ugeplaner</div>
          <div style={{ fontSize: 12, color: "#6A5A50", fontFamily: "'Nunito', sans-serif", marginBottom: 14 }}>Skift mellem børn eller tilføj et nyt</div>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {(profiles || []).map(p => (
              <div key={p.id} style={{
                display: "flex", alignItems: "center", gap: 12,
                background: p.id === activeProfile?.id ? `${acc}15` : "#F8F4FF",
                borderRadius: 16, padding: "12px 14px",
                border: p.id === activeProfile?.id ? `2px solid ${acc}` : "2px solid transparent",
              }}>
                <span style={{ fontSize: 28 }}>{p.avatar || "🦁"}</span>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 15, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif" }}>{p.name}</div>
                  <div style={{ fontSize: 11, color: "#8A7A90", fontFamily: "'Nunito', sans-serif", fontWeight: 600 }}>{THEMES.find(t => t.id === p.themeId)?.label || "Lyng"} tema</div>
                </div>
                {p.id !== activeProfile?.id && (
                  <button onClick={() => { setActiveProfileId(p.id); try { localStorage.setItem("ugeplan_active", p.id); } catch {} }} style={{
                    background: acc, color: "#FFFFFF", border: "none", borderRadius: 999,
                    padding: "7px 14px", fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 12,
                    cursor: "pointer", boxShadow: `0 3px 10px ${acc}40`,
                  }}>Skift til</button>
                )}
                {p.id === activeProfile?.id && (
                  <div style={{ fontSize: 11, fontWeight: 800, color: acc, fontFamily: "'Nunito', sans-serif" }}>Aktiv ✓</div>
                )}
                {(profiles || []).length > 1 && (
                  <button onClick={() => {
                    if (!window.confirm(`Slet ${p.name}s ugeplan? Dette kan ikke fortrydes.`)) return;
                    const next = profiles.filter(x => x.id !== p.id);
                    setProfiles(next);
                    saveProfiles(next);
                    if (p.id === activeProfileId) {
                      setActiveProfileId(next[0]?.id || null);
                      try { localStorage.setItem("ugeplan_active", next[0]?.id || ""); } catch {}
                    }
                  }} style={{
                    background: "#FFE4E4", color: "#DC2626", border: "none", borderRadius: 999,
                    width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center",
                    cursor: "pointer", fontSize: 14, flexShrink: 0,
                  }} title="Slet">✕</button>
                )}
              </div>
            ))}
            <button onClick={() => setAddingChild(true)} style={{
              display: "flex", alignItems: "center", gap: 10,
              background: `${acc}15`, border: `2px dashed ${acc}60`,
              borderRadius: 16, padding: "12px 14px", cursor: "pointer",
              fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 14, color: acc,
            }}>
              <div style={{ width: 36, height: 36, borderRadius: 12, background: grad, display: "flex", alignItems: "center", justifyContent: "center", boxShadow: `0 3px 10px ${acc}40` }}>
                <span style={{ fontSize: 20, color: "#FFFFFF" }}>+</span>
              </div>
              Tilføj et barn
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  // Sync theme when active profile changes
  React.useEffect(() => {
    if (activeProfile?.themeId) setThemeId(activeProfile.themeId);
  }, [activeProfile?.id]);

  // Save theme change back to profile
  const handleSetThemeId = (tid) => {
    setThemeId(tid);
    if (activeProfile) {
      setProfiles(prev => {
        const next = prev.map(p => p.id === activeProfile.id ? { ...p, themeId: tid } : p);
        saveProfiles(next);
        return next;
      });
    }
  };

  // No profiles yet → show first-time onboarding
  if (!profiles) {
    return (
      <OnboardingScreen onDone={({ childName: name, themeId: tid, avatar }) => {
        const profile = makeProfile(name || "Barn", tid, avatar);
        const newProfiles = [profile];
        setProfiles(newProfiles);
        setActiveProfileId(profile.id);
        setThemeId(tid);
        saveProfiles(newProfiles);
        try { localStorage.setItem("ugeplan_active", profile.id); } catch {}
      }} />
    );
  }

  // Adding a new child
  if (addingChild) {
    return (
      <OnboardingScreen isAddingChild onDone={({ childName: name, themeId: tid, avatar }) => {
        const profile = makeProfile(name || "Barn", tid, avatar);
        const newProfiles = [...profiles, profile];
        setProfiles(newProfiles);
        setActiveProfileId(profile.id);
        setThemeId(tid);
        setAddingChild(false);
        saveProfiles(newProfiles);
        try { localStorage.setItem("ugeplan_active", profile.id); } catch {}
      }} />
    );
  }

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Nunito:ital,wght@0,400;0,600;0,700;0,800;0,900;1,800&display=swap');
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; -webkit-tap-highlight-color: transparent; }
        html, body { background: ${activeBg}; transition: background 0.4s ease; }
        ::-webkit-scrollbar { display: none; }

        button { transition: transform 0.14s cubic-bezier(0.34,1.56,0.64,1), opacity 0.12s, background 0.18s, box-shadow 0.18s; }
        button:active { transform: scale(0.90) !important; opacity: 0.88; }

        .card-row { transition: background 0.2s, transform 0.14s cubic-bezier(0.34,1.56,0.64,1), box-shadow 0.18s, opacity 0.2s; }
        .card-row:active { transform: scale(0.97) !important; }

        .card-bounce { animation: cardBounce 0.45s cubic-bezier(0.34,1.56,0.64,1); }
        @keyframes cardBounce { 0%{transform:scale(0.85) translateY(10px);opacity:0} 100%{transform:scale(1) translateY(0);opacity:1} }

        .tab-pip { transition: all 0.25s cubic-bezier(0.34,1.56,0.64,1); }

        @keyframes spin { to { transform: rotate(360deg); } }
@keyframes pulse { 0%,100% { opacity: 0.4; } 50% { opacity: 0.9; } }
@keyframes doneOverlay {
          0%   { opacity: 0; transform: scale(0.6); }
          60%  { transform: scale(1.08); }
          100% { opacity: 1; transform: scale(1); }
        }
        @keyframes checkPop {
          0%   { transform: scale(0) rotate(-20deg); }
          60%  { transform: scale(1.3) rotate(5deg); }
          100% { transform: scale(1) rotate(0deg); }
        }

        .drop-flash { animation: dropFlash 0.4s ease; }
        @keyframes dropFlash { 0%{transform:scale(1.04)} 50%{transform:scale(0.98)} 100%{transform:scale(1)} }

        .header-gradient { position: relative; overflow: hidden; }
        .header-gradient::after {
          content: ''; position: absolute; inset: 0;
          background: radial-gradient(ellipse at 70% 20%, rgba(255,255,255,0.18) 0%, transparent 60%);
          pointer-events: none;
        }

        .progress-glow { filter: drop-shadow(0 0 6px rgba(255,255,255,0.6)); }

        @media print {
          @page { margin: 0; }
          body > * { display: none !important; }
          #print-root { display: block !important; }
          #print-root > * { display: flex !important; }
          * { -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; }
        }
      `}</style>

      <div style={{ maxWidth: 430, margin: "0 auto", minHeight: "100dvh", background: activeBg }}>
        <div style={{ overflowY: "auto", height: "calc(100dvh - 84px)" }}>
          {tab === "week"     && renderWeek()}
          {tab === "day"      && renderDay()}
          {tab === "library"  && renderLibrary()}
          {tab === "routines" && renderRoutines()}
          {tab === "theme"    && renderTheme()}
        </div>

        {/* Tab bar */}
        {/* Tab bar — floating pill */}
        <div style={{ position: "fixed", bottom: 0, left: "50%", transform: "translateX(-50%)", width: "100%", maxWidth: 430, zIndex: 200, padding: "0 12px 16px" }}>
          <div style={{ background: "rgba(255,255,255,0.88)", backdropFilter: "blur(20px)", WebkitBackdropFilter: "blur(20px)", borderRadius: 999, padding: "6px 6px", display: "flex", alignItems: "center", justifyContent: "space-around", boxShadow: "0 8px 32px rgba(0,0,0,0.14), 0 2px 8px rgba(0,0,0,0.08)" }}>
            {[
              { id: "week",     icon: "week",     label: "Uge" },
              { id: "day",      icon: "day",      label: "Dag" },
              { id: "library",  icon: "library",  label: "Bibliotek" },
              { id: "routines", icon: "routines", label: "Rutiner" },
              { id: "theme",    icon: "theme",    label: "Tema" },
            ].map(t => (
              <button key={t.id} onClick={() => setTab(t.id)} style={{
                display: "flex", flexDirection: "column", alignItems: "center", gap: 3,
                background: tab === t.id ? grad : "transparent",
                border: "none", cursor: "pointer", flex: 1,
                padding: "10px 4px 8px", borderRadius: 999,
                boxShadow: tab === t.id ? `0 4px 14px ${acc}50` : "none",
                transition: "all 0.22s cubic-bezier(0.34,1.3,0.64,1)",
              }}>
                <Icon name={t.icon} size={22} color={tab === t.id ? "#FFFFFF" : "#8A7A90"} />
                <span style={{ fontSize: 10, color: tab === t.id ? "#FFFFFF" : "#8A7A90", fontFamily: "'Nunito', sans-serif", fontWeight: 900 }}>{t.label}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Label edit overlay */}
        {editLabelCard && (
          <div style={{ position: "fixed", inset: 0, background: "rgba(26,8,64,0.55)", zIndex: 600, display: "flex", alignItems: "center", justifyContent: "center", padding: "0 24px", backdropFilter: "blur(6px)" }}
            onClick={() => setEditLabelCard(null)}>
            <div onClick={e => e.stopPropagation()} style={{ background: "#FFFFFF", borderRadius: 28, padding: "28px 24px 24px", width: "100%", maxWidth: 360, boxShadow: "0 12px 48px rgba(26,8,64,0.25)" }}>
              <div style={{ fontSize: 56, textAlign: "center", marginBottom: 8 }}>{editLabelCard.picto.emoji}</div>
              <div style={{ fontSize: 16, fontWeight: 900, color: "#1A0840", fontFamily: "'Nunito', sans-serif", textAlign: "center", marginBottom: 20 }}>Rediger navn</div>
              <input
                autoFocus
                value={editLabelCard.tempLabel}
                onChange={e => setEditLabelCard(prev => ({ ...prev, tempLabel: e.target.value }))}
                onKeyDown={e => { if (e.key === "Enter") saveLabel(editLabelCard.picto, editLabelCard.tempLabel); if (e.key === "Escape") setEditLabelCard(null); }}
                style={{
                  width: "100%", boxSizing: "border-box",
                  padding: "14px 16px", fontSize: 18, fontWeight: 800,
                  fontFamily: "'Nunito', sans-serif", color: "#1A0840",
                  background: "#F8F4FF", border: `2.5px solid ${acc}`,
                  borderRadius: 16, outline: "none", textAlign: "center",
                  marginBottom: 16,
                }}
              />
              <div style={{ display: "flex", gap: 10 }}>
                <button onClick={() => setEditLabelCard(null)} style={{ flex: 1, padding: "13px 0", background: "#F0EBF8", border: "none", borderRadius: 999, fontFamily: "'Nunito', sans-serif", fontWeight: 800, fontSize: 14, color: "#6A5880", cursor: "pointer" }}>Annuller</button>
                <button onClick={() => saveLabel(editLabelCard.picto, editLabelCard.tempLabel)} style={{ flex: 2, padding: "13px 0", background: acc, border: "none", borderRadius: 999, fontFamily: "'Nunito', sans-serif", fontWeight: 900, fontSize: 14, color: "#FFF", cursor: "pointer", boxShadow: `0 4px 16px ${acc}50` }}>Gem navn</button>
              </div>
            </div>
          </div>
        )}

        {/* Overlays */}
        {/* Routine print overlay */}
        {showRoutinePrint && (
          <RoutinePrintOverlay
            routines={ROUTINE_TEMPLATES}
            theme={theme}
            grayscale={grayscale}
            onClose={() => setShowRoutinePrint(false)}
          />
        )}
        {showRoutines && (
          <RoutineOverlay
            theme={theme}
            onApply={(template, days) => {
              days.forEach(day => {
                template.cards.forEach(c => addCard(day, { ...c, uid: undefined }));
              });
            }}
            onClose={() => setShowRoutines(false)}
          />
        )}

        {/* Timer overlay */}
        {showTimer && (
          <TimerOverlay
            timerLeft={timerLeft}
            timerSecs={timerSecs}
            timerRunning={timerRunning}
            onStart={startTimer}
            onPause={() => setTimerRunning(false)}
            onReset={resetTimer}
            onSetTime={(s) => { setTimerSecs(s); setTimerLeft(s); setTimerRunning(false); }}
            onClose={() => setShowTimer(false)}
            theme={theme}
          />
        )}

        {/* Share overlay */}
        {showShare && (
          <ShareOverlay
            shareUrl={getShareUrl()}
            pin={sharePIN}
            onClose={() => setShowShare(false)}
            theme={theme}
          />
        )}

        {bankFor && (
          <BankOverlay library={library} onSelect={p => addCard(bankFor, p)} onClose={() => setBankFor(null)} onOpenGenerate={() => { setBankFor(null); setGenerateFor(bankFor); }} onOpenSclera={() => { setBankFor(null); setShowSymbolSearch(true); }} theme={theme} grayscale={grayscale} scleraIcons={scleraIcons} />
        )}
        {showSymbolSearch && grayscale && (
          <SymbolSearchOverlay
            theme={theme}
            onSelect={p => {
              const newPicto = { id: p.id || ("sclera_" + Date.now()), ...p };
              setLibrary(prev => [newPicto, ...prev]);
              if (bankFor) addCard(bankFor, newPicto);
            }}
            onClose={() => setShowSymbolSearch(false)}
          />
        )}
        {generateFor && (
          <GenerateOverlay
            onAdd={picto => {
              const newPicto = { id: uid(), ...picto };
              setLibrary(prev => [newPicto, ...prev]);
              if (generateFor !== "__lib" && generateFor !== "__standalone") addCard(generateFor, newPicto);
            }}
            onClose={() => setGenerateFor(null)} theme={theme}
          />
        )}
        {editingCard && (
          <CardEditorOverlay
            card={editingCard.picto}
            isNew={editingCard.isNew}
            theme={theme}
            onSave={data => saveToLibrary(data, editingCard.isNew ? null : editingCard.picto)}
            onDelete={editingCard.isNew ? null : () => deleteFromLibrary(editingCard.picto.id)}
            onClose={() => setEditingCard(null)}
          />
        )}
        {addingToDay && (
          <AddToDayOverlay
            picto={addingToDay}
            week={week}
            onAdd={day => addCard(day, addingToDay)}
            onClose={() => setAddingToDay(null)}
            theme={theme}
          />
        )}
        {showPrint && (
          <PrintOverlay
            week={week}
            theme={theme}
            grayscale={grayscale}
            focusDay={focusDay}
            scleraIcons={scleraIcons}
            onClose={() => setShowPrint(false)}
          />
        )}
      </div>
    </>
  );
}

